INSERT INTO `llm_model` (`model_id`, `model_name`, `model_tag`, `provider`, `description`, `created_at`) VALUES
(1, 'Llama 3.2 3B Instruct', 'llama3.2:3b', 'Meta', 'Meta Llama 3.2 3B instruction-tuned model. Selected as a compact general-purpose baseline that runs comfortably on medium-specification machines while retaining solid multilingual comprehension for EN-MS code-switched nutritional extraction.', '2026-07-01 06:38:50'),
(2, 'Phi-4-mini 3.8B Instruct', 'phi4-mini', 'Microsoft', 'Microsoft Phi-4-mini 3.8B instruction-tuned model. Selected as an efficiency benchmark, offering strong reasoning density per parameter at a small footprint suitable for CPU-based batch processing of cooking transcripts.', '2026-07-01 06:38:50'),
(3, 'Qwen 2.5 3B Instruct', 'qwen2.5:3b', 'Alibaba', 'Alibaba Qwen 2.5 3B instruction-tuned model. Selected for its broad multilingual coverage including Malay and English, providing a general multilingual reference point for code-switched gastronomy transcript analysis.', '2026-07-01 06:38:50'),
(4, 'Gemma-SEA-LION v4 4B', 'aisingapore/Gemma-SEA-LION-v4-4B-VL', 'AI Singapore', 'AI Singapore Gemma-SEA-LION v4 4B model, post-trained on Southeast Asian languages including Malay on a Gemma 3 base. Selected to test whether regional language adaptation improves extraction accuracy on EN-MS code-switched cooking transcripts compared with general multilingual models.', '2026-07-01 06:38:50'),
(5, 'MedGemma 4B', 'medgemma:4b', 'Google', 'Google MedGemma 4B model adapted for medical and biomedical text on a Gemma 3 base. Selected to evaluate whether domain-specific pretraining improves nutritional information extraction accuracy relative to general-purpose instruction-tuned models.', '2026-07-01 06:38:50');
