(807, 2876, 'Recipe #22 (Transcript 22)', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '```json\n{\n  \"recipe_name\": \"\",\n  \"servings_estimated\": 0,\n  \"ingredients\": [\n    {\n      \"ingredient_name_original\": \"ulas bawang putih\",\n      \"quantity_value\": 5,\n      \"quantity_unit_original\": \"ibu jari\"\n    },\n    {\n      \"ingredient_name_original\": \"lengkuas\",\n      \"quantity_value\": 1,\n      \"quantity_unit_original\": \"ibu jari\"\n    },\n    {\n      \"ingredient_name_original\": \"seketul kunyit hidup\",\n      \"quantity_value\": 2,\n      \"quantity_unit_original\": \"biji (kayu-kayu)\",\n      \"estimated_weight_g_per_bijian\": null\n    },\n    {\n      \"ingredient_name_original\": \"sudu kecil biji ketumbar\",\n      \"quantity_value\": 1,\n      \"quantity_unit_original\": \"sudu\"\n    },\n    {\n      \"ingredient_name_original\": \"jinten putih\",\n      \"quantity_value\": 1,\n      \"quantity_unit_original\": \"sudu (daging jinten)\"\n    },\n    {\n      \"ingredient_name_original\": \"dua biji buah keras\",\n      \"quantity_value\": 2\n    },\n    {\n      \"ingredient_name_original\": \"bunga lawang\",\n      \"quantity_value\": 2,\n      \"estimated_weight_g_per_bilirung\": null\n    }\n  ],\n  \"nutrition_total\": {\n    \"calories\": 0,\n    \"protein_g\": 0,\n    \"total_carbohydrate_g\": 0,\n    \"total_fat_g\": 0\n  },\n  \"instructions\": [\n    \"Ambil lima ulas bawang putih, halia sebesar ibu jari; lengkuas sebesar ibu jari; seketul kunyit hidup (dua biji), satu sudu kecil biji ketumbar, satu sudu kecil jintan putih. Blending dengan air.\",\n    \"Blend blended mixture with two bunga lawang and also dua buah pelaga until it becomes fragrant.\",\n    \"Add deux batang serai yang telah dimasak; duas helai daun salam atau bay leaf; satu helal daun kunyit; bawang besar. Masukkan satu sudu cili kisar.\",\n    \"Continue cooking until oil starts to separate, then add chicken.\",\n    \"Utilize een kotak kecil santan (chicken broth); tambahkan air. Use tiga ke empat helai daun limau purut for aromatics and seasoning with gula garam as needed.\",\n    \"If the color is not satisfactory, add another sudu cili kisar to achieve a reddish hue.\"\n  ]\n}\n```', 1, '2026-07-01 22:00:48'),
