INSERT INTO `transcript` (`transcript_id`, `reel_id`, `audio_id`, `file_name`, `file_path`, `file_created_at`, `file_size_bytes`, `file_format`, `audio_transcript_consistent`, `verified_by_matric`, `verified_by_name`, `verified_at`, `content`) VALUES
(1, 1, 1, 'transcription_DV-gOghkxnP.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DV-gOghkxnP.txt', NULL, NULL, 'txt', 1, 'B032410535', 'ZUBAIRAH BINTI ZULKIFLI', '2026-07-01 08:41:37', 'Okay, what\'s up guys. So ini adalah video masak kedua terakhir sebab esok kita ada lagi satu sahaja video\nand then habislah sesi per sekolahan kita. Sedihnya.\nOkay, kita nak buat puding buah naga.\nKau orang ambil satu tin susu cair, dua cawan fresh milk,\nsatu cawan air, and then setengah cawan susu pekat,\nlepas tu tambah setengah cawan air laici dalam tin tu.\nLepas tu kau orang masukkan satu paket agar-agar, yang ni 10 gram.\n10 gram, jangan lebih.\nOkay, lepas tu kau orang asingkan dua bekas macam ni sama rata pun tak apa.\nLepas tu kita lenyekkan satu biji buah naga.\nPotong kecil-kecil baru senang lenyek sikit.\nLepas tu kau orang campurkan buah naga tu ke dalam satu portion kuah kita buat tadi.\nLagi satu portion tu pula, kau orang letak hirisan buah laici dalam tin tadi.\nLepas tu kau orang masak.\nMasak buah laici dulu, bagi dia panas sikit, medidih sikit terus padamkan api\nand letak dalam bekas-bekas cantik.\nMacam ni lah, tema kita kan open house tahun ni.\nSo senang.\nTak perlu letak, tak perlu letak dalam peti sejuk tau.\nBagi dia cool down sekejap, bagi dia menggeras sikit, baru kau orang masak layer buah naga ni pula.\nSama juga, dah mula panas mendidih sikit, baru kau orang tuang ke atas layer laici di bawah tu.\nAnd then kau orang bagi dia cool down dekat luar.\nKalau ada buih-buih ke atas, hilangkan buih tersebut. \nLetakkan hirisan buah naga lagi, tutup, barulah kita letak dalam peti sejuk.\nAnd bila tetamu dah datang, dah boleh hidang cantik bekas dia.\nElok kan rupa dia.\nNak lagi extra, boleh letakkan lagi balance air laici dalam tin tadi ke atas.\nBagi dia lagi moist, lagi sedap lah.\nDan kau orang akan dapat rasa buah naga dengan laici sangat lah.\nPerfectly harmonised together.\nMakan sangat sedap.\nYang ni tak perlu open house pun tak apa.\nNak buat untuk berniaga lepas raya nanti pun boleh juga.\nOkay, stay tune. Esok one more recipe.\nHmm, dah.\nRasa laici dengan buah naga, ibarat dikahwinkan bersama-sama.\nBerjodoh.\nYang ni wajib makan sejuk-sejuk.\nOkay.\nBolehlah buat untuk open house raya nanti.\nSelamat Hari Raya.\r\n'),
(2, 2, 2, 'transcription_DV7uZzBE47j.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DV7uZzBE47j.txt', NULL, NULL, 'txt', 1, 'B032410535', 'ZUBAIRAH BINTI ZULKIFLI', '2026-07-01 08:41:37', 'Okay what\'s up guys, so ini resepi kuah kacang yang korang boleh save siap-siap\nboleh buat malam raya nanti dengan family\nuntuk resepi ni KA guna setengah kilo kacang tanah\nmasak atas kuali tak perlu letak minyak, masak dengan api pelahan\nkacang-kacang sampai dia garing macam ni lebih kurang 15 ke 20 minit lah\nyang boleh letak kat tepi sejukkan\nyang kalau perasaan kulit dia mudah tertanggal\nso korang boleh ketinggirkan dia kat atas jaring macam ni senang\nsupaya kulit jatuh bawah, kacang yang bersih duduk kat atas\nlepas tu kita boleh blend\ncara dia senang saja, korang ambil lebih kurang 70% kacang tadi\nkorang blend secara halus, lagi 30% korang blend secara kasar\nratio tu optional lah, depend, nak kasar lebih ke, nak halus lebih ke boleh\nlepas tu letak kacang kita kat tepi dulu sebab next kita nak buat ketupat pula\nso kita perlukan ketupat minyak\nyang ni KA pakai daripada kecil lagi mak masakkan kat rumah\nsenang, sebab packaging dia food grade, selamat, korang boleh masak\ndan korang akan dapat nasi impit yang padat tapi lembut kat dalam\nbila dah masak boleh sejukkan kat tepi dulu\nnext korang ambil lebih kurang 4 bawang merah\n3 batang serai, lengkuas dengan halia sebesar ibu jari\n3 biji buah keras dengan 16 bawang putih\nkorang blend, KA terlupa masukkan sekali 1 sudu udang kering\nlepas tu blend, kita akan nak masak sekarang ni minyak masak kena banyak\nnak buat kuah kacang jangan kedekut minyak\nkena bagi minyak banyak\nlepas tu masukkan 5 sudu cili kisar\nyang ni KA pakai yang tak pedas, kalau pedas kena kurangkan sikit\nok, next kita kacau sampai pecah minyak\nlepas tu kita masukkan kacang tadi\nnampak macam kering, jangan risau, tambahkan air\ndan masa ni korang kena sabar sikit\nproses dia akan lama sikit\nkorang kena masak dengan api yang jangan besar\ntunggu sampai dia kering sikit, masukkan air\nlepas tu masak lagi, bila kering sikit masukkan air lagi\nmasak lagi, sampailah kacang kat dalam tu lembut\nlebih kurang 20 minit macam tu, KA masaklah\nand then masukkan 3 ketul kecil gula melaka\ngaram dengan sebut perasa secukupnya dengan setengah sudu\npes asam jawa, kalau tak ada pes\nnak pakai air asam jawa pun boleh, agak-agak je nanti\nmasak-masak sampai siap\nnampak tak bila kita masak dengan perlahan\nakan dapat kuah kacang berkilat, cantik, elok, merah macam ni\nlepas tu korang ambil nasi impik yang dah sejuk tadi\nboleh potong bentuk dalam pun padat, cantik\nok, so kita boleh serve kat atas pinggan\nyang ni sangat simple, straightforward\nserve dengan kacang macam ni sahaja\nkalau nak extra, tak nak kalah kan\nboleh makan dengan satay sekali\nok, so korang boleh ambil turn masak kuah kacang tahun ni\nconfirm family akan suka nanti\nterharunya boleh buat kuah kacang sendiri\nsedap, rasa lemak kacang tu\nmasin, manis, gula melaka perfect\ncampur dengan nasi impik yang lembut ni Allah\nsenang je sebenarnya nak buat kuah kacang dekat rumah\nboleh try untuk masak hari raya nanti\nselamat hari raya\r\n'),
(3, 3, 3, 'transcription_DV5HVWMk059.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DV5HVWMk059.txt', NULL, NULL, 'txt', 1, 'B032410535', 'ZUBAIRAH BINTI ZULKIFLI', '2026-07-01 08:41:37', 'Hey, what\'s up, guys? Menu dessert untuk open house raya belum habis.\nSiapa yang in charge dessert untuk raya ni minta maaf.\nMenekan-nekan tahun ni banyak betul resipi dessert.\nKita nak buat chocolate chip muffin.\nKorang ambil 2 biji telur, 3 per empat cawan gula.\nKorang whisk sampai dia kembang lebih kurang 4 ke 5 minit.\nDia kembang putih macam ni lah.\nMasukkan setengah cawan minyak masak, setengah cawan fresh milk ataupun full cream milk pun boleh.\nTambahkan 2 cawan tepung gandum.\nAnd then, 1 penutup esen vanila, 2 sudut kecil baking powder, setengah sudut kecil garam.\nAnd then, kita gaul. Gaul pakai tangan je, dek.\nGaul sampai sebati macam ni.\nLepas tu kita letak chocolate chip.\nKA, guna lebih kurang 1 cup, 1 cawan.\nNak pakai semi-sweet, boleh dark chocolate pun boleh. Tak kisahlah.\nLepas tu pergi supermarket ataupun kedai bakery, cari kita punya muffin cup ni.\nTak kisah saiz berapa.\nKorang buat layer kat bawah.\nLetakkan chocolate hazelnut dan juga additional chocolate chip dekat tengah.\nYang ini optional. Kalau tak nak pun tak apa.\nLepas tu letak lagi satu layer kat atas.\nDia lebih kurang 3 per empat penuh lah.\nAnd then, baru korang taburkan chocolate chip lagi kat atas.\nAnd bakar pada suhu 180 celcius selama 22 minit.\nDia akan keluar cantik, golden brown.\nElok macam ni.\nBila korang koyak, paper cup tu boleh nampak dia fluffy kat dalam.\nAda melted chocolate lagi inside there.\nOh, sangatlah sedap makan panas-panas.\nOkay, selamat mencuba.\nSedap, ya?\nSangat simple, sangat sedap.\nPenuh dengan chocolate kat dalam.\nBoleh buat untuk open house raya nanti, ya.\nSelamat hari raya.\r\n'),
(4, 4, 4, 'transcription_DV2roeAk7aZ.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DV2roeAk7aZ.txt', NULL, NULL, 'txt', 1, 'B032410535', 'ZUBAIRAH BINTI ZULKIFLI', '2026-07-01 08:41:37', 'Kepada adik-adik yang tak pernah buat bihun goreng,\nRaya ni KA nak cabar korang masuk dapur,\nmasakkan sepaket bihun goreng ni untuk family.\nBeritahu mak, mak, adik nak masak bihun lah, biar adik buat sendiri.\nCuba ambil cabaran ni tengok jadi ke tak.\nSo korang ambil satu paket bihun, rendam dengan air paip biasa je,\ntak perlu air suam lah, tak perlu air panas lah.\nAmbil 2 bawang merah, 3 ulas bawang putih dengan segengam kecil ikan bilis,\nkorang blend, lepas tu masukkan cili kisar.\nKalau kurang pedas, letak lebih. Kalau pedas, pakai sikit sahaja.\nLepas tu boleh letak seafood, fish cake, fish ball,\nni tuan rumah yang jenis pemurah lah ni, seafood banyak.\nDoakanlah dia dimurahkan rezeki eh.\nMasukkan air sikit, tambahkan 2 sudu sos tiram,\n4 sudu kicap manis, 2 sudu sos tomato,\n4 sudu sos cili,\nlepas tu korang cari kat supermarket ni petis udang,\nyang ni optional.\nKalau ada lagi sedap, masukkan setengah sudu makan sahaja.\nIngatlah eh, optional. Tak wajib. Jangan menekan-nekan.\nOkey, lepas tu baru masukkan bihun tu.\nPerasan tak bila kita letak bihun ni,\ndia nampak macam tak meresap sangat kuah tu.\nDia nampak keras, nampak macam dry.\nDon\'t worry. Korang kacau je.\nSaya masukkan sos ikan. Banyak-banyak pun tak apa lagi sedap.\nAnd then baru tambahkan garam dan serbuk perasa secukupnya.\nLepas kita letak sos ikan tadi tu lah.\nSambung masak, bihun akan mula lembut.\nDia akan mula serap semua kuah-kuah dalam tu.\nBaru korang masukkan sayur sawi dengan lada besar yang kita slice nipis-nipis macam ni lah.\nKacau-kacau-kacau. Nampak tak? Dia dah cantik.\nTak berminyak sangat, tak basah sangat, tak kering sangat.\nKorang akan dapat perfect konsistensi bihun goreng yang just nice boleh makan di hari raya nanti.\nNak lagi sedap, boleh taburkan daun sup dan bawang goreng.\nNak bagi kurkak-kurkak sikit.\nAtaupun nak lagi best, korang boleh periksa pinggan.\nMakan sekali dengan kondimens lah.\nMacam korang boleh letakkan keropok goreng.\nLepas tu nak letak cili potong pun boleh.\nYang KA guna ni ada cili jeruk. Yang daripada botol pun tak kisahlah.\nLetak bagi rasa pedas sikit, barulah makan.\nOkay, cuba buat.\nNak tengok result macam mana korang buat.\nUntuk hari raya nanti.\nMasak bihun ni mudah lah. Tapi kalau salah buat, memang tak jadi.\nAnd not best boleh makan dengan keropok keping sekali.\nPlease lah try. Selamat mencuba dan selamat hari raya.\r\n'),
(5, 5, 5, 'transcription_DVxhUWTk6SJ.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DVxhUWTk6SJ.txt', NULL, NULL, 'txt', 1, 'B032410535', 'ZUBAIRAH BINTI ZULKIFLI', '2026-07-01 08:41:37', 'Hei wassup guys, hari ni kita nak buat puding jagung creamy dengan kuah custard ke atas\nkorang boleh hidang sejuk-sejuk\nbagi tetamu makan open house raya nanti sangat lah senang nak buat\nfirst korang perlukan satu tin jagung yang creamy ni\ntambahkan satu tin susu cair\nlepas tu tambah satu kotak kecil santan\ndua per tiga cawan susu pekat\nlepas tu korang tambahkan satu per tiga cawan cordial jagung\nmana-mana brand pun boleh tak kisah\ntambahkan satu cawan air\nlepas tu setengah sudu kecil garam\ndan juga sirap sikit nak bagi warna dia lagi cantik lah\nlepas tu baru masukkan satu cawan tepung custard\ntepung custard ni kena larutkan awal sebelum kita masakkan\nmasuk last minute dia berkeladak dik tak cantik\nkorang masak sampai dia pekat, likat, cantik\nmacam ni dah masak\nboleh angkat yang ni kena cepat\nlambat sikit dia akan beku\nletak dalam bekas yang korang nak\nnak bekas macam ni boleh, nak letak dalam tray pun boleh\nlepas tu hentak-hentak sikit\nbagi keluar any bubbles\nand yang ni optional korang boleh ambil jagung yang seketul-seketul dalam tin tu\nboleh letak ke atas bagi dia extra kruk-krak lah\nambil satu tin susu cair\nsetengah tin air\nand then masukkan tiga sudu susu pekat\ndengan satu sudu setengah\ntepung custard\nlepas tu korang masakkan, sama juga\ntunggu sampai dia mendidih panas sikit\nbaru korang angkat\nand kuah tu dah pekat boleh letak ke atas kita punya pudding tadi\nitu sahaja\nsangat simple\ntutup kita punya bekas lepas dia dah cool down sikit\nand boleh simpan lepas dia sejuk\nbila dia keluar, tadaa\njemput masuk, selamat hari raya\nboleh lah makan ambil satu bekas seorang\nlepas tu boleh makan\nnampak tak texture dia sangat lembut\nand korang akan dapat pudding yang gedik-gedik\nmacam azfarheri macam ni\nsangat sedap makan sejuk-sejuk\noh rasa lemak jagung\nyang ni kalau haus kejap-kejap habis ni\nselamat mencuba\r\n'),
(6, 6, 6, 'transcription_DVu00H3kp9L.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DVu00H3kp9L.txt', NULL, NULL, 'txt', 1, 'B032410535', 'ZUBAIRAH BINTI ZULKIFLI', '2026-07-01 08:41:37', 'Hey what\'s up guys, kalau sebelum ni aku risau tengok students buat pudding caramel\nhari ni bertambah lagi risau sebab kita nak buat salted caramel cornflakes\ndia sangatlah senang dan sedap nak buat, tolong jangan berasap dapur\nSedap ya\nOkay cara dia senang saja korang ambil 2 cawan gula\napi jangan besar sangat, lepas tu korang pusing\npusing abang Jamil, sampai lah dia dah mula cair\ntapi kalau masih berketul kat tengah tak apa korang ambil sendok dah boleh kacau\nsebab time ni dia tak melekat dekat sendok tu lah\nOkay lepas tu kita masukkan 1 cawan whipping cream\nmake sure cream tu suhu bilik supaya tak terbakar macam tu\nOkay faham tak, kacau-kacau lagi, masa ni dah boleh padamkan api lah\nand then masukkan 1 blok unsalted butter\nokay, butter ni lebih kurang 200g satu blok macam tu lah\nOkay lepas tu masukkan 1 penutup esen vanila dengan 1.5 sudu kecil garam\nkalau korang pakai salted butter, garam tu boleh kurangkan sikit kat sini lah\nOkay lepas tu untuk cornflakes ni pula depends, nak pakai yang nipis boleh\nnak pakai yang tebal pun boleh, cuma yang ni korang kena decide\nKalau korang nak yang extra manis korang lebihkan caramel, kurangkan cornflakes\nKalau korang nak yang kurang manis, lebihkan cornflakes, kurangkan caramel\nmacam tu sahaja\nSo yang KA pakai ni sepaket 500g cornflakes yang versi nipis sikit\nbukan yang tebal lah, lepas tu rata kat atas tray\nand kita boleh bakar dalam oven lebih kurang 170 celcius selama 5 minit\nnak bagi dia lagi kukrak-kukrak sikit, tahan lama lah\nOkay lepas tu tu je lah\nand korang boleh dengar bunyi kukrak-kukrak macam tu\nboleh simpan lah, bagi dia sejuk dulu tau\nbagi dia betul-betul sejuk baru korang boleh simpan\nJadi sebabkan aku malas nak letak dalam paper cup kecil macam tu\naku letak dalam balang macam ni je\nkalau budak datang beraya, dek, kau ambil je dalam tu dek\nAbang malas nak letak dalam paper cup\nOkay siap dah kita punya cornflakes salted caramel\nsangatlah wangi bau dia\nSo itu sahaja methode dia, sangat senang sebenarnya\ncuma korang kena pay attention buat betul-betul\nSedapnya\nCornflakes kita crunchy, tak lemau\nand dia punya caramel tak pahit, tak hangus\nJust nice perfect dengan garam salted kat dalam tu\nSo boleh lah buat untuk kuih raya korang nanti\nSelamat mencuba\nTolonglah guys, jangan gagal\nkorang dah practice dengan pudding caramel insyaAllah menjadian ni\r\n'),
(7, 7, 7, 'transcription_DVpyGdQktC.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DVpyGdQktC.txt', NULL, NULL, 'txt', 1, 'B032410535', 'ZUBAIRAH BINTI ZULKIFLI', '2026-07-01 08:41:37', 'What\'s up, guys? Selamat datang ke kelas pertama biskut raya kita tahun ini.\nHa yang mana masih buat lauk pauk tu. Kita dah move on lah.\nKita nak move on pergi ke biskut raya pula.\nHari ini kita nak buat butter cookies. Sangatlah senang, sangat sedap.\nKorang ambil 125g unsalted butter.\nYang ini lebih kurang separuh block butter yang kita beli kat supermarket tu lah.\nTambahkan dua per tiga cawan icing sugar. Korang mix.\nMake sure butter tu room temperature lah.\nTambahkan satu putih telur.\nDua sudu kecil esen vanila dengan garam sikit.\nKacau-kacau sampai dia sebati macam ni.\nAnd then kita masukkan satu sudu makan tepung jagung.\nBaru tambahkan satu cawan tepung gandum.\nKacau sikit lepas tu korang masukkan lagi satu per empat cawan tepung gandum.\nSo total tepung gandum satu satu per empat cawan lah.\nLepas tu korang ambil nozzle, muncung nozzle yang bentuk macam ni untuk piping bag.\nIsi dalam piping bag ni.\nLepas tu kita ready. Ready nak pipingkan dia lah.\nBentuk dia sangatlah senang. Buat bulat macam tu, cuat naik ke atas.\nSangat senang. Aku buat sekali dua pun dah menjadi dah.\nKalau dia kadang-kadang besar, kadang-kadang kecil tu.\nTak apalah, dik nak makan kat rumah je.\nSo sangat senang nak buat. Jangan risau.\nLepas tu tabur lah. Tak sure nak panggil apa ni.\nBerbola manik ke kalfur rice ke apa ke tabur kat atas.\nBakar pada suhu 170 celsius selama 15 minit.\nDan dia akan keluar cantik. Golden Brown kat luar macam tu.\nDan tengah masih lagi lembut.\nSo rasa dia memang buttery.\nSangat sedap. Tak manis sangat.\nAnd the best part dia senang nak buat.\nSo boleh panggil satu family. Budak-budak sekali pun boleh join buat untuk malam raya nanti.\nAtau pun boleh buat sekarang.\nBoleh simpan dalam jar macam ni.\nAnd ready untuk hari raya.\nVery simple, senang nak buat.\nAnd the best part dia tak manis sangat.\nSo korang boleh buat dengan anak-anak nanti.\nMakan untuk hari raya.\nSelamat mencuba.\r\n'),
(8, 8, 8, 'transcription_DVnQtx_Acua.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DVnQtx_Acua.txt', NULL, NULL, 'txt', 1, 'B032410535', 'ZUBAIRAH BINTI ZULKIFLI', '2026-07-01 08:41:37', 'Hey what\'s up guys tengah tengok jam ke tu sabar kita ada dua air spesial yang korang boleh buat hari ni untuk buka puasa ataupun boleh buat untuk open house raya nanti\nanda kena start plan daripada sekarang lah\nok first kita nak buat tembikai rose sparkling\nyang ni sangat lah senang korang ambil tembikai fresh potong cube\npotong cube cantik macam ni patut hiriskan limau kasturi and also buah laici\nand kita perlukan Sunquick campuran rose laici yang mana belum pernah try pergi supermarket ambil yang ni\nyang ni favourite KA rasa rose laici tu very strong very sedap\ncampur dengan air biasa pun dah cukup tapi yang ni kita nak spesial kita campurkan air sparkling\nlagi fizi rasa dia lah\npastu korang masukkan hirisan tembikai kita letak tadi\nmasukkan laici, nata de coco, lepas tu masukkan limau kasturi, daun pudina itu sahaja\nnah kacau-kacau-kacau\nnak senang dia boleh serve dalam mangkuk\nso bila tetamu datang nanti macam eh rumah ni hidang apa eh\noh ada mangkuk boleh serve dalam tu\nsangat lah practical sebab apa kita banyak topping kat dalam so lagi senang dia orang scoop dengan sudu boleh kunyah\ntrust me rasa dia sangat sedap, refreshing, masam-masam manis rasa rose laici kena try\napa sedap\nok next kita nak buat watermelon oren cooler\nyang ni rasa dia lagi masam-masam lah\nsangat senang korang hiriskan buah oren yang ni kita akan buat topping nanti\nlepas tu korang ambil buah tembikai kita akan blend dengan air sikit\nand masukkan air kosong ataupun air sparkling yang guna tadi pun boleh juga\nkorang akan dapat texture yang slushy, ice blended macam yang cantik, that\'s it\nok lepas tu masukkan ais and kita perlukan Sunquick oren\nyang ni original flavour kalau pergi raya, open house setiap rumah hidangkan air Sunquick ni memang sangat-sangat popular di air raya\nso why not kita bagi twist sikit korang letak dalam jug\nand masukkan juga sikit Sunquick campuran rose laici tadi\nbaru kita tuangkan watermelon laici yang kita blend tadi nampak tak dia punya texture\nsangat meniurkan\nletakkan hirisan oren kita potong awal tu\nitu saja, sangat senang korang boleh nampak color dia sangat-sangat terang, vibrant tu\nrasa oren dia and tembikai dia very well blended\nyang ni lagi unique dia rasa oren dia quite strong\ntapi kita campur dengan tembikai semua\nsangat sedap untuk buat open house raya nanti ok\nselamat berbuka dan selamat hari raya\r\n'),
(9, 9, 9, 'transcription_DVnHYwNE75z.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DVnHYwNE75z.txt', NULL, NULL, 'txt', 1, 'B032410535', 'ZUBAIRAH BINTI ZULKIFLI', '2026-07-01 08:41:37', 'Hey what\'s up guys, minta maaf lah semalam takde kelas. Bukanlah MC, lebih kepada ponteng lah sebenarnya.\nTapi tak apa, hari ni kita ganti balik, kita nak buat macaroni goreng untuk open house raya.\nCara dia korang ambik daging frozen, lebih kurang 400 gram.\nMacam biasa tak perlu letak minyak, kita goreng dulu bagi dia keluar dia punya lemak-lemak semua itu.\nBagi garing sikit, baru kita angkat letak kat tepi.\nOkay next, korang ambik 3 bawang merah dengan 6 ulas bawang putih, korang chop chop chop.\nLepastu kita tumis, masukkan 1 hingga 2 sudu cili kisar lah.\nNak lebih pedas, lebihkan. Tak nak pedas, kurangkan.\nDia punya kerak-kerak daging kat tepi kual itu jangan risau.\nKorang tambahkan air dan korang akan deglazekan dia.\nAh nampak tak? Itu semua flavor, jangan buang tahu.\nMasukkan daging tadi, tambahkan 2 sudu sos tiram, 2 sudu sos tomato, 2 sudu sos cili dan 3 sudu kicap manis.\nSebab itu korang tambahkan 1 cube pati ayam.\nKacau kacau ni kita punya base kuah lah.\nOkay untuk macaroni pula, portion dia korang ambik 1 paket yang lebih kurang 400 gram.\nSo recipe KA buat ni perfect untuk satu family makan, cukup satu tray.\nSo korang rebus macaroni tu dengan garam sikit, lepas tu kita masukkan dalam tumisan tadi.\nAnd gaul, gaul-gaul. Nampak tak?\nDia punya sebati kuah itu melekat elok dekat kita punya macaroni tu.\nLepas tu korang tambahkan sikit, lada benggala merah, hijau, kuning, tak kisah warna traffic light.\nNaik seri sikit kita punya macaroni tu.\nLepas tu lengkapkan seasoning dia, letakkan garam, serbuk perasa kacau-kacau.\nAnd siap boleh serve dalam tray.\nTahun ni memang makanan open house aku buat.\nBanyak bertemakan tray sebab senang nak serve kepada tetamu.\nNak lagi best korang kena banyakkan hirisan daun sup and also bawang goreng dekat atas.\nYang ini lebih kan, lagi banyak lagi sedap.\nLepas tu nak lagi kick, perahkan sikit limau nipis kat atas baru lagi surr dia punya rasa.\nAnd siap lah kita punya macaroni goreng boleh buat untuk open house raya.\nAtau pun boleh buat terus berbuka malam ni.\nWow!\nI\'m amazed korang tabur banyak-banyak bawang goreng dengan daun sup tu.\nLepas tu perah limau sikit, sangat sedap.\nNanti boleh buat untuk open house raya korang.\nSelamat Hari Raya!\r\n'),
(10, 10, 10, 'transcription_DVh7unGE58A.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DVh7unGE58A.txt', NULL, NULL, 'txt', 1, 'B032410535', 'ZUBAIRAH BINTI ZULKIFLI', '2026-07-01 08:41:37', 'Ini resipi spaghetti bolognese versi lokal tapi sebelum kongsi resipi ni saya Khairul Aming\nIngin membuat disclaimer bahawa saya bukan orang Itali\ntidak dilahirkan di Itali dan tidak pernah ke Itali\nResipi ini dibuat menggunakan bahan yang jumpa di Kedai Runcit sahaja\nTiada tomato Itali digunakan dan tiada daging fresh digunakan\nDaging beku yang jumpa dalam freezer di Kedai Runcit digunakan sebab sesuai dengan bajet orang ramai\nIni bukan resipi authentic, try at your own ways\nHei, what\'s up guys?\nOk, first korang ambil daging frozen\nTak kisahlah brand Ramli ke mana-mana brand lebih kurang 400 gram\nKorang tak perlu letak minyak tau, biar dia punya lemak cair sendiri\ndan dia akan garingkan sendiri dia punya daging tu\nOk, bila dah garing sikit korang boleh bawa kuang letak tepi dulu\nAnd then korang perlukan 1 batang celery, 1 bawang holland, 1 carrot dengan 4 ulang bawang putih\nAnd chop chop chop chop, bagi dia hancur sikit\nLepas tu kita tumiskan, tumis bagi dia layu sampai dia golden brown sikit kat tepi\nAnd kita perlukan tomato puree\nIni pakai satu tin, tak mana-mana brand pun tak kisah\nTuangkan kat dalam\nAnd korang blend 2 biji tomato fresh\nBlend 2 biji letakkan air sikit\nLepas tu korang, apa orang kata masukkan daging tadi\nAnd tambahkan setengah sudu makan oregano\nDengan satu sudu makan chilli flakes\nNak bagi dia pedas sikit lah\nLepas tu masukkan garam, black pepper cukupnya\nTambahkan sehelai daun salam ataupun bay leaf\nDengan satu cube pati lembu\nKalau orang tanya, eh tak jumpa lah cube pati ayam boleh ke?\nAmbil lah adik, whatever yang ada lah cube pati ayam pun boleh\nTambahkan air dan korang tutup\nDan biarkan dia masak lebih kurang 15 minit\nLagi lama lagi sedap\nKalau dia kering tambahkan air sikit\nSupaya kita dapat kuah yang pecah minyak berkilap merah\nElok macam ni rupa dia\nUntuk spaghetti pula jangan pening\nFollow je instruction belakang packaging\nKalau dia kata 8 minit, 8 minit lah korang rebus\nKalau kata 10, 10 minit\nLepas tu letak dalam tray\nAnd tetamu pun dah sampai\nJemput masuk, buka celipar\nBoleh self serve sendiri letak dalam pinggan spaghetti\nLetakkan kita punya kuah bolognese kat atas\nTaburkan parmesan cheese kat atas\nAnd sedia untuk dihidang\nYang ni boleh makan kenyang-kenyang\nAku rasa tak tunggu open house ni\nMalam ni pun korang boleh buat\nMasak dengan family untuk berbuka\nMmm, enaknya\nAku rasa boleh buat esok open house ni\nWeh jadi weh\nOkey boleh buat terus nanti\nUntuk puas raya ataupun makan malam ni terus\nUntuk buka puasa\nOkey, selamat berbuka\r\n'),
(11, 11, 11, 'DL1btPEPGyg.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DL1btPEPGyg.txt', NULL, NULL, 'txt', 1, 'B032510777', 'FAIZ HADIF BIN FAZRAN', '2026-07-01 08:41:37', 'Hey what\'s up guys, hari ni kita nak buat durian crepe yang gebu-gebu macam bantal\nlepas tu penuh isi durian kat dalam. Senang dia nak buat sebenarnya\nkorang ambil setengah cawan tepung gandum, setengah cawan tepung ubi kayu, dua sudu tepung jagung\ndua biji telur, and then tambah satu cawan fresh milk, nak pakai full cream pun boleh\nand then setengah cawan air, satu sudu minyak masak garam sikit, and then food colour warna kuning\nyang ni nak guna hijau merah ke tak kisah korang blend lepastu korang tapis\nlepastu panaskan kuali, baru tuangkan adunan tu\nlebihan adunan buang balik dalam bekas tadi\nso kita nak create yang nipis saja\nand kuali tu kena panas tapi jangan panas sangat\nso masak sampai dah tak melekat boleh bawa keluar lah\nok awal-awal memang akan confirm fail\nmemang confirm ke gagal, buat banyak kali sampai jadilah\nok next kita nak non-dairy cream\nyang ni boleh beli dekat kedai bakery banyak jual\nkena pakai non-dairy cream, barulah cream kita tu cantik yang tak runtuh\ntak lembik lah orang kata eh\nlepas tu untuk durian pula, pakai je durian mana yang korang nak\nyang ni lebihan musang king ada lagi semalam\nsebab budak-budak ni pergi beli 2 bakul\nso kita lenyek kan\nresepi ni tak perlu letak gula ke apa\nsebab cream tu macam dah manis\ndurian pun dah manis jugak\nso letak layer by layer lah, cream durian cream\nand then lipat\ncuma aku punya kulit crepe ni besar sangat\nso banyak lebihan\nkalau lipat semua jadi tebal sangat\nso terpaksa lah koyak lebihan tu\nso kalau korang ada kuali kecil-kecil\npakai kecil-kecil lagi better lah kurangkan pembaziran\nminta maaf lah kalau crepe orang lain cantik, elok\nmacam bantal hotel\naku punya macam bantal busuk\ntapi tak apa, don\'t judge the crepe\nby its cover\nyang penting kat dalam tu interior padat\ndurian cream semua sedap makan kat rumah sejuk-sejuk\nokay, selamat mencuba\n'),
(12, 12, 12, 'DLzOCUSP-2V.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DLzOCUSP-2V.txt', NULL, NULL, 'txt', 1, 'B032510777', 'FAIZ HADIF BIN FAZRAN', '2026-07-01 08:41:37', 'Hey, what\'s up, guys?\nSo, sekarang kan musim durian.\nKalau kita bawa kereta kiri kanan depan belakang menjual durian.\nJadi, hari ni kita nak buat serawa durian.\nJadi, dia senang. Dia ambil satu cawan air,\ntambah 3 helai daun pandan,\n3 ketul kecil gula melaka,\ndan dia masukkan 2 kotak kecil santan.\nLepas itu untuk durian, korang boleh pakai mana-mana durian korang nak.\nTapi, budak-budak ni, dorang mengada sikit.\nNak bermanja-manja, dia macam ming nak musang king.\nSo, kita masuk musang king dalam serawa ni.\nKorang boleh guna 15 ulas durian macam tu.\nLepas itu, masak. Masak sampailah kuah tu pekat.\nAnd then, durian tu dah mula lerai kat dalam.\nKita akan dapat kuah yang macam custard, creamy macam ni lah.\nAnd then, tambahkan garam secukupnya untuk balancekan rasa.\nYang ni, korang boleh adjust.\nKalau pekat sangat, tambahkan air sikit.\nKalau tak cukup manis, tambahkan gula melaka.\nBoleh adjust lah.\nAnd sedia untuk dihidang panas-panas.\nYang ni, sedap. Makan cicah dengan roti pun boleh.\nNak makan dengan pulut pun boleh.\nPulut tu next video.\nAku dah siap record dah semalam tapi tak edit lagi.\nNanti kita akan upload.\nOkay? Selamat mencuba.\n'),
(13, 13, 13, 'DK_apWevSEW.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DK_apWevSEW.txt', NULL, NULL, 'txt', 1, 'B032510777', 'FAIZ HADIF BIN FAZRAN', '2026-07-01 08:41:37', 'Hey, what\'s up guys?\nYa Allah, lama ni tak buat video masak.\nRindu pelajar-pelajar cikgu.\nOkay, hari ni kita nak buat video daging belengas\nmenggunakan daging raya haji\ndalam peti sejuk.\nKorang tak bawak keluar daripada hari tu lagi tu.\nSo korang boleh keluarkan daging.\nKalau nak sedap, tambahkan lemak sikit lah.\nLepas tu kita akan rebus.\nRebus tu dalam 30 minit sampai daging tu empuk\ndan sampai air dia kering macam ni.\nOkay?\nLepas tu korang tambahkan satu sudu kecil serbuk kunyit\nand then masukkan minyak masak\nsebab kita nak bagi dia garang-garang sikit.\nAnd then korang blend 7 bawang putih\ndengan seketul halia.\nLepas tu masukkan.\nLepas tu ambil kicap caramel\ndengan kicap manis.\nKalau tak ada kicap caramel, guna kicap manis sahaja.\nTambahkan sos cili, sos tomato\ndan juga sos tiram.\nSos tiram perlu lebih sikit\nbaru sedap lah.\nRecipe ni kita campak-campak sahaja.\nTak perlu major sangat lah.\nTambahkan garam serbuk perasa secukupnya.\nKalau kering sangat, masukkan air sikit.\nLepas tu masukkan bawang holland,\ncili padi dengan kacau panjang.\nLepas tu kacau-kacau siap lah.\nBoleh makan dengan nasi putih.\nYang simple je.\nAku pun berapa-apa masa lama ni\ntak buat video masak.\nRindu.\nTapi tak apalah.\nKalau tak ada,\nmungkin next year pula\naku muncul balik lagi sekali.\nTapi resipi ni khas untuk korang\nyang ada daging, raya haji\nkat rumah tak tahu nak masak apa.\nBoleh dah buat keluar\ndaripada peti sejuk tu\ndan masak malam ni dengan family.\nSelamat mencuba.\n'),
(14, 14, 14, 'DKROoWRv1ce.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DKROoWRv1ce.txt', NULL, NULL, 'txt', 1, 'B032510777', 'FAIZ HADIF BIN FAZRAN', '2026-07-01 08:41:37', 'Kalau tiba-tiba mengidam nak makan telur mata kicap, boleh makan sekali dengan dendeng.\nJadi dia senang sahaja korang goreng 2 biji telur mata,\ntambahkan hirisan bawang merah, lepas tu tambahkan cili padi, letakkan kicap.\nNak perah limau sikit pun boleh.\nLepas tu kita boleh hidang dengan dendeng nyet extra pedas.\nYang ini versi baru, lagi pekat, lagi pedas, lagi kick dia punya rasa.\nCili pun kita letak berkali-kali, ganda lagi banyak dekat dalam ni lah.\nSo korang boleh makan.\nYang ni alhamdulillah ramai repeat order dalam masa 3 minggu dan lebih 100,000 unit terjual.\nSo kalau nak grab boleh makan kat rumah atau bawa pergi travel.\nYang ni lagi pedas, lagi kick daripada yang original hari tu.\nSo kalau korang nak grab, boleh pergi ke Bio IG KA tu.\nTekan link dia kat situ and straight pergi ke Shopee, boleh add to cart and buat payment kat situ lah.\nThank you guys.\n'),
(15, 15, 15, 'DIaj0R9Shng.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DIaj0R9Shng.txt', NULL, NULL, 'txt', 1, 'B032510777', 'FAIZ HADIF BIN FAZRAN', '2026-07-01 08:41:37', 'Cuba bayangkan tengah-tengah malam tiba-tiba mengidam nak makan nasi putih dengan telur mata.\r\nFirst kita masak nasi, kemudian goreng telur mata ni kalau boleh bagi kuning telur tu lembik-lembik lagi sedap.\r\nBila kita ambil dendeng nyet berapi, alhamdulillah sekarang dah lebih daripada 1 juta paket terjual.\r\nDan kita tambah lagi sambal nyet berapi kat atas untuk bagi lagi extra pedas.\r\nAnd then sedia untuk dihidang.\r\nBoleh letakkan kita punya dendeng nyet dengan sambal kat atas nasi yang panas-panas yang boleh terus makan.\r\nSo dendeng dengan sambal tak perlu nak masak, it\'s ready to eat.\r\nBoleh makan bila-bila masa sahaja, nak bawa pergi travel, bawa camping, asrama, college pun sangat sesuai.\r\nSo kalau nak dapatkan dendeng dan juga sambal nyet berapi, boleh pergi ke Shopee Khairul Amin Brand atau tekan link di bio.\r\n'),
(16, 16, 16, 'DHsGA4xSh5g.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DHsGA4xSh5g.txt', NULL, NULL, 'txt', 1, 'B032510777', 'FAIZ HADIF BIN FAZRAN', '2026-07-01 08:41:37', 'What\'s up guys, so korang boleh save recipe ni siap-siap\nkalau raya nanti open house tak tahu nak masak apa\nboleh buat recipe ni, nasi tomato dengan ayam masak merah ala kenduri\nambil 3 sudu minyak sapi, rempah 4 sekawan\n3 biji bawang merah, 3 ulas bawang putih\nand then goreng kejap, lepas tu masukkan 1 cube pati ayam\nhalia sebesar ibu jari\n4 sudu tomato dalam tin tu, masukkan sehelai 2 daun pandan\nand the tambahkan 1 sudu gula, 1 per 3 sudu garam\nlepas tu tambahkan setengah cawan susu cair\nitu sahaja dia punya sukatan\nuntuk beras pula ambil 4 cawan beras basmati\ntapi korang kena rendam dalam air lebih kurang setengah jam dulu\nbaru korang masakkan dengan 5 cawan air\n4 cawan beras masakkan dengan 5 cawan air\ntapi beras tu kena rendam dulu setengah jam\nmasak nasi macam biasa\nuntuk ayam pula korang ambil ayam, gaulkan dengan garam dengan kunyit\ngoreng sampai dia golden brown, garing macam ni\nnext korang ambil 2 biji bawang holland\n4 biji bawang merah dengan 8 ulas bawang putih\nkorang blend dengan air\nlepas tu masukkan 1 batang serai dengan 1 helai daun pandan\ntumis sekali dengan bahan tumis tadi\ncili kisar ni nak pedas letak lebih, kalau tak nak kurangkan\ntapi kalau aku ni kuali kecil pindah kuali besar sikit\ntumis sampai dia pecah minyak dah hilang pahit bawang tu\nmasukkan 1 tin kecil tomato\ntambahkan 2 sudu sos tiram, 2 sudu sos cili\ndengan garam, subuk rasa gula semua tu\ndan bila dia pecah minyak lagi sekali masukkan ayam tadi\ndia tambahkan hirisan bawang holland, hirisan cili\ndan kemudian tomato\nlepas tu nak lagi creamy, lagi sedap dia punya kuah tu\ntambahkan 1 per tiga cawan susu cair dalam tin tu\nlepas tu siap itu sahaja\nkacau-kacau kita punya ayam masak merah la kenduri ni siap\ntapi tak tahu siapa yang kenduri nak kawin tu\nyang pasti bukan akulah\nlepas tu kita boleh hidang\nletakkan dengan nasi\nnasi dah siap belum?\ndah siap dah\ntapi segala jenis rempah ratus kat atas tu bawa kuah dulu la\nnanti kau nangis dik, kalau tergigit buah pelaga tu nanti\nboleh hidang dengan nasi\nacar ni kek tak sempat nak record korang cari lah\nresipi dia senang sahaja, tak ada masalah\nboleh buat untuk apa haus?\nraya nanti\nselamat hari raya\n'),
(17, 17, 17, 'DHpwG1MSeF3.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DHpwG1MSeF3.txt', NULL, NULL, 'txt', 1, 'B032510777', 'FAIZ HADIF BIN FAZRAN', '2026-07-01 08:41:37', 'Hey what\'s up guys, untuk menu open house yang seterusnya, kita nak buat laksa siam.\nIni sangat sedap dan senang dia nak buat sebenarnya.\nBoleh slup-slup satu rumah makan.\nCara dia, korang ambil satu kilo ikan kembung, korang rebuskan dengan dua asam keping.\nRebus sampai ikan itu masak, boleh bawa keluar.\nAir rebusan itu jangan buang, kita nak guna lepas ini untuk blend.\nUntuk ikan tadi pula, korang tunggu sejuk, kemudian korang asingkan.\nKita ambil isi dia dahulu.\nTulang letak tepi, ambil isi sahaja.\nIni korang blend dengan air rebusan dari sampah dia lumat macam ni.\nBoleh letak kat tepi dulu.\nKemudian tulang yang lebih tadi pula dengan kepala ikan tu, korang blend juga dengan air rebusan tadi.\nCuma yang ni korang kena tapis, sebab dalam tu banyak duri-duri tajam tak elok tertelan nanti.\nOkay next, korang ambil dua bawang merah, tiga batang serai, halia sebesar ibu jari, lengkuas sebesar ibu jari.\nDua ketul kunyit hidup, enam ulas bawang putih, dua belas cili padi dengan seketul kecil belacan yang dibakar.\nOkay, pasal kita blend, pasal letak dalam periuk tak perlu minyak, masukkan isikan kita dah blend tadi dengan tulang, air tulang sekali.\nOkay, pasal simple je, dia memang campur macam ni sahaja, tak perlu minyak apa pun.\nLepas tu, bila mendidih, masukkan tiga kotak kecil santan, dan korang tambah empat helai daun limau purut dengan dua asam keping.\nAnd then nak bagi kuning sikit lagi cantik, tambahkan serbuk kunyit sikit lagi.\nLepastu tambah lah kita punya seasoning, garam, gulai, serbuk, perasa semuanya.\nAnd then, bila nak siap masak, tambahkan daun selasih thai ataupun thai basil.\nKalau tak jumpa juga tak apalah, it\'s okay. Boleh skip sahaja.\nLepas tu, gunakan laksa ini, KA kira paket, senang.\nLepas tu, celupkan laksa tu, tuang kita punya kuah, letak topping, toge, timun, bunga kantan, apa yang korang suka.\nItu sahaja. Sangatlah sedap dan senang korang boleh buat untuk open house raya dengan family nanti.\n'),
(18, 18, 18, 'DHfgOT-y8vZ.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DHfgOT-y8vZ.txt', NULL, NULL, 'txt', 1, 'B032510777', 'FAIZ HADIF BIN FAZRAN', '2026-07-01 08:41:37', 'Hey what\'s up guys, so dalam petis sejuk korang ada lagi tak daging frozen hari tu?\nBawa keluar sebab kita nak buat cheesy oblong burger.\nMasukkan daging kisar yang frozen tu, and then masukkan garam dengan black pepper,\ngoreng sekejap, lepas tu masukkan separuh biji bawang holland, sambung goreng sampai dia mula garing-garing sikit lah.\nAmbil roti oblong, sapukan butter, ada roti burger biasa pun boleh je sebenarnya.\nAnd then letakkan cheese, nak bagi cheese tu menitik cantik, kau renjiskan 2-3 titik air, tutup dengan protok periuk tu.\nTunggu sekejap dia akan steam kat dalam lah.\nDan sedia boleh letak kat tepi, jangan tak cukup nafas hari dua ni.\nLepas tu letakkan kita punya daging, now kita nak buat sauce.\nSauce kita ambil separuh cawan mayo, tambahkan pickle.\nPickle ni timun jeruk kat supermarket ada jual.\nLepas tu masukkan mustard, letakkan cuka, sikit cuka, jangan banyak nanti dia masam.\nTambahkan garlic powder, black pepper dan juga 2 sudu chilli sauce.\nKalau orang tanya, kenapa tak pakai sauce tomato macam Mat Saleh?\nBoleh tapi aku macam tak pedas, dia nak kena ada kick juga, so chilli sikit.\nKita tekak Malaysia kan, lepas tu letakkan sayur kat tepi, letaklah tomato ke lettuce ke kepit dan sedia untuk dihidang.\nActually awal-awal aku nak buat roti John sebenarnya ala-ala inspired roti John.\nAku lupa nak letak telur kat roti tu tapi tak apalah boleh je, macam ni pun dah sangat-sangat sedap dah.\nSebenarnya korang boleh buat untuk moreh dengan family malam ni.\nYang ni senang je, confirm jadi. awas kalau tak jadi.\nSelamat mencuba!\n'),
(19, 19, 19, 'DHaQzydSNs3.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DHaQzydSNs3.txt', NULL, NULL, 'txt', 1, 'B032510777', 'FAIZ HADIF BIN FAZRAN', '2026-07-01 08:41:37', 'Hei wassup guys, adakah dah habis resepi yang menggunakan tepung dan juga yis?\nJawapannya belum. Kita ada lagi satu resepi hari ni iaitu chocolate beignet.\nYang ni senang budak darjah lima pun boleh buat.\nOkay, first ambil 3 per empat cawan air suam, tambahkan 1 paket yis, kacau-kacau-kacau, tunggu 5 minit.\nLepas tu masukkan setengah cawan susu sejat, tambahkan 1 per 3 cawan gula, 3 sudu butter yang dicairkan,\n1 sudu kecil vanila, 1 biji telur, dengan setengah sudu kecil garam.\nKacau-kacau-kacau, lepas tu masukkan 4 cawan tepung gandum, tepung gandum dik, bukan tepung ubi kayu, tepung gandum.\nLepas tu uli-uli untuk orang yang macam KA, saya tak biasa lah nak uli tepung, practice, kena belajar dik.\nuli-uli sampai dia tak melekat dekat mangkuk tu, tutup, lepas tu biarkan sejam.\nLepas sejam macam biasa, dia akan always akan kembang macam ni.\nKalau tak kembang, yis kau dah meninggal sebenarnya.\nLepas tu kena lenyekkan sikit, and letak tepung atas cutting board supaya dia tak melekat,\nkau orang lenyekkan sampai dia nipis macam ni, lepas tu kita potong jadikan petak.\nYang lebihan tu jangan buang tahu, kau orang boleh gentel balik, lenyekkan balik macam biasa.\nYang ni KA buat putih petak-petak, ketebalan dough yang kita lenyek tadi tu lebih kurang macam ni.\nDia tak tebal sangat, tak nipis sangat.\nReason kita buat nipis tu supaya bila goreng, dia akan gelembung, ada udara kat dalam,\nand dia jadi crispy.\nDia macam bola-bola macam tu, nak tengok rupa dia je, tunggu eh.\nAda lagi letak hazelnut ke, nak letak kaya ke, apa lagi lah.\nCaramel cake tapak kuda ke sumpat di dalam tu.\nLepas tu letakkan powder sugar kat atas, and sedia untuk dihidang lah.\nYang ni lupa letak topping. Lagi satu, yang ni terlebih pula topping dia.\nBanyak sangat meleleh.\nAku rasa yang ni baru cantik dia punya ratio.\nYang ni just nice.\nBalance antara topping dan juga kita punya beignet kat luar tu.\nSo selamat mencuba.\n'),
(20, 20, 20, 'DHNX6dsSUba.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DHNX6dsSUba.txt', NULL, NULL, 'txt', 1, 'B032510777', 'FAIZ HADIF BIN FAZRAN', '2026-07-01 08:41:37', 'Hey what\'s up guys, hari ni kita nak buat resepi yang paling elegant bulan puasa tahun ni\niaitu cheesy garlic bread yang buat daripada scratch dekat rumah\nyang ni sangat senang nak buat, korang ambik satu cawan fresh milk\ntambahkan setengah cawan air dan dia panaskan dalam 30 saat\nsekejap je, kita nak bagi susu tu warm sikit je\ndan dia masukkan satu per tiga cawan gula dengan satu paket yis\nlepas tu korang kacau-kacau-kacau\nand then lepas 5 minit dia akan boom kembang macam ni lah\nmasukkan 2 digit telur dan korang tambahkan 4 cawan tepung roti\ntambah lagi setengah cawan, so total 4/5 cawan\ntepung roti eh, bukan tepung gandum, kat supermarket ada banyak jual\nlepas tu masukkan 1/5 sudu kecil garam\nand pergi supermarket cari QBB, minyak sapi tulen\nini dah banyak saiz lah, yang kecil sampai besar pun ada\nyang best ni dia 100% pure daripada lemak susu\ntak ada bahan capuran, tak ada flavouring\nsebab tu warna dia gold cantik macam ni lah\nso kita guna 2 sudu minyak sapi ni\ncairkan dan dia letakkan atas kita punya adunan roti tadi\nok next kita gaulkan semua\nyang ni part penting anak-anak, please dengar and listen\nsetiap orang yang guna telur berbeza-beza saiz\nso akan ada dough yang lagi lembab\nataupun basah daripada 2 orang lain\nso korang kena tambahkan lagi 3-4 sudu tepung roti tu\nsampai lah dia tak melekat dah\nkorang punya dough tu dekat mangkuk\ndia keluar cantik macam ni lah\nso kita bagi dia kembang lebih kurang sejam\ngerbuk besar macam ni\nlepas tu korang boleh buka\nnampak tak sangat fluffy, nyok-nyok lagi kalau kita tekan kat situ tu\nboleh buat keluar dan kita ready untuk potong lah\ndia senang je, dia nampak macam banyak step tapi senang je sebenarnya\nkorang potong, kalau nak potong secara kasar\nnak agak-agak macam ni guna pisau pun boleh\nnak lagi accurate boleh pakai penimbang lah\nsupaya dia punya roti dia semua sama saiz\nso ini korang gentil jadikan bulat\nleperkan macam ni sikit\ntambahkan mozzarella cheese kat dalam\nyang ni korang ambil dan picit-picit kat bawah tu\nkumpulkan kat tengah, pusing sikit\nlepas tu korang letak atas cutting board balik\nand korang roll balik jadi bulat macam ni lah\nso repeat sampai semua kita bebola-bebola roti ni dah ready\nletak dalam kita punya loyang\nnampak tak cantik susunan dia, fit just nice kat dalam tu\nso korang bagi dia kembang lagi 30 minit\ngerbuk jadi macam tu\nand then kita ambilkan telur\npukulkan sebiji\ndan kita sapu sikit kat atas\ningat bagi warna golden brown cantik dekat kita punya roti nantilah\nbakar dalam oven pada suhu 190 celcius\nlebih kurang 18 ke 20 minit macam tu\nand then kita nak buat dia punya ni pula\nkorang ambil 2 sudu minyak sapi ataupun ghee tadi\ntambahkan 10 hulas bawang putih\ngaram sikit dengan daun parsley\ndaun parsley tu optional lah\nkalau tak ada pun tak apa\nlepas tu boleh sapu kat atas kita punya roti\ntadi roti aku automatik jadi berkilat\nini yang bagi aroma garlic and parsley yang fresh\ndekat kita punya roti lah\ndan sedia untuk dihidang\naku sampai sekarang tak percaya yang boleh buat kat rumah roti ni\nserius aku macam speechless jugak lah\nsangat fluffy kat dalam lembut\ndan rasa garlic yang strong\ntapi balance dengan kita punya cheese tu\nso boleh lah try nanti\nbest buat dekat rumah\ntexture roti tu sangat-sangat fluffy\ndan rasa garlic yang strong campur dengan cheese kat dalam\naku tak boleh percaya yang boleh buat kat rumah roti macam ni\nrasa macam beli kat kedai okey\nnanti boleh try untuk moreh dengan family nanti okey\nselamat mencuba\n'),
(21, 21, 21, 'DZMs_V5z0Z_.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DZMs_V5z0Z_.txt', NULL, NULL, 'txt', 1, 'B032410624', 'HANIS ALYSHA BINTI RAHAMI', '2026-07-01 21:29:37', 'Hey, what\'s up guys. Lamanya tak masak, minta maaflah. Cikgu biasanya kalau cuti sekolah tiga bulan sekali cuti, ha. So hari ni kita nak buat menu daging korban. Yang mana dalam freezer tu, korang keluarkan daging korban sebab kita nak buat daging balado.\r\nCara dia, korang ambil daging tu lepas tu kita hiriskan. Tak perlu nipis sangat, tak perlu tebal sangat sebab nanti kita akan tumbuk. Lepas tu korang ambil setengah sudu makan biji ketumbar, korang tumbukkan dengan enam ulas bawang putih. Tumbuk-tumbuk sampai lumat. Aku punya lesung ni pun last guna bulan puasa hari tu. Haa letak korang punya daging tu, masukkan bahan tumbuk tadi, satu batang serai, satu daun salam dengan satu sudu kecil garam. Lepas tu korang tambahkan air, and kita rebuslah. Rebus lebih kurang setengah jam. Kalau air tu kering cepat sangat, korang tambahlah sikit air lagi. Tapi rebus lebih kurang sampai air dah kering macam ni lah, and daging tu akan jadi lembut.\r\nSo sekarang kita akan tumbuk daging tu. Yang ni jangan geram sangat, jangan marah sangat, tumbuk lembut-lembut je, ha. Bagi dia carik-carik sikit, and then kita goreng. Time ni goreng tak sampai seminit pun, dia akan keluar garing golden brown macam ni, and sangat crispy and lembut kat dalam lah.\r\nLepas tu korang ambil sepuluh lada besar, tiga ulas bawang merah, satu tomato dengan cili padi tu depends, kalau nak pedas tambahkan banyaklah. Lepas tu korang hiriskan lada ni, hiris dua tahu, kalau tak nanti dia akan meletup masa goreng. So korang goreng sampai dia layu, garing sikit macam ni, lepas tu boleh angkat, and kita lenyek guna lesung. Lenyek-lenyek bagi lumat, cuma yang lada besar tu bagi dia kasar sikit, baru cantik dia punya tekstur bila kita masak nanti lah.\r\nSo korang tumis, tapi minyak tu dah kurangkanlah, pakai sikit saja. And then korang tambahkan dua helai daun limau purut, setengah kiub pati ayam, and tambahkan kita punya seasoning, garam gula serbuk perasa secukupnya, gaul-gaul-gaul, and siap! Sedia untuk dihidang. Tapi tak apa, belum lagi. So nak lagi kick, korang perahkan sikit limau kasturi bagi dia rasa macam-macam kick kat situ. Lepas tu bolehlah hidang dengan nasi putih. Haa ni simple je KA buat, letak nasi putih, letak kita punya daging tu kat atas, lepas tu tambahkan kicap manis. Lepas tu gaul-gaul-gaul, bolehlah makan. Itu saja. Nak lagi extra, korang gorenglah telur mata ke, nak buat sambal belacan ke, apa-apa pun boleh, no problem. Sekian sahaja. Bulan puasa nanti lah aku muncul lagi sekali eh. Nak kembali menghilang pula, haha. Selamat mencuba.'),
(22, 22, 22, 'DVQGyKJE-Qs.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DVQGyKJE-Qs.txt', NULL, NULL, 'txt', 1, 'B032410624', 'HANIS ALYSHA BINTI RAHAMI', '2026-07-01 21:29:37', 'Hey, what\'s up guys. Hari tu korang dah buat ayam pop kan? Sabar. Ada lagi satu subjek kita nak buat untuk kedai nasi padang kita, iaitu gulai ayam padang. Yang ni sangat sedap, kuah dia pekat sangat.\r\nSo ambil lima ulas bawang putih, halia sebesar ibu jari, lengkuas sebesar ibu jari, seketul kunyit hidup, satu sudu kecil biji ketumbar, satu sudu kecil jintan putih, dua biji buah keras, lepas tu korang blend dengan air. Dan lepas blend kita akan tumiskan bersama dengan dua bunga lawang and also dua buah pelaga. Tumis, tumis sampai dia naik bau semua. Barulah kita masukkan dua batang serai yang dah diketuk, dua helai daun salam ataupun bay leaf, satu helai daun kunyit, bawang besar, lepas tu masukkan satu sudu cili kisar. Cili kisar tu akan bagi kita punya warna gulai ni lagi merahlah.\r\nTumis sampai pecah minyak, and baru kita masukkan ayam. Ada orang tanya, \"KA, asyik ayam je, tak ada ke protein lain, itik, angsa ke?\" KA guna ayam sebab senang nak dapat, semua orang boleh masaklah. And baru kita masukkan satu kotak kecil santan, tambahkan air. And then untuk aromatics dia, kita akan guna tiga ke empat helai daun limau purut. Lepas tu masukkan seasoning lah, gula garam secukup rasanya. Tapi warna dia tak cukup merahlah. Aku nak merah lagi, so aku tambahkan lagi satu sudu cili kisar. So total kita pakai dua sudu lah, senang saja, simple saja resipi ni.\r\nBila ayam dah empuk dan lembut, ni extra kalau nak, keluarkan ayam dulu, pastu keluarkan segala serdak kat dalam, serai, bunga lawang apa semua tu bawa keluar, and then kita blend kita punya kuah supaya dapat tekstur berkilat, pekat, glossy, silky smooth macam ni. Lepas tu kita boleh serve kat atas ayam kita, kuah tadi, and sedia untuk dihidang.\r\nYang ni perfect makan dengan nasi putih. Nak lagi extra, korang buat lauk yang kita buat hari tu lah, sambal tempe, lepas tu buat ayam pop, pastu air es jeruk pun ada aku buat hari tu, alhamdulillah jadi, ah, dah jadi kedai nasi padang kat rumah pula. Tapi kalau rajin, boleh gabungkan semua lauk together lah. So, selamat berpuasa dan selamat berbuka.');
INSERT INTO `transcript` (`transcript_id`, `reel_id`, `audio_id`, `file_name`, `file_path`, `file_created_at`, `file_size_bytes`, `file_format`, `audio_transcript_consistent`, `verified_by_matric`, `verified_by_name`, `verified_at`, `content`) VALUES
(23, 23, 23, 'DVQQaLWE4i9.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DVQQaLWE4i9.txt', NULL, NULL, 'txt', 1, 'B032410624', 'HANIS ALYSHA BINTI RAHAMI', '2026-07-01 21:29:37', 'Hey, what\'s up guys. Yang mana yang masuk masak puding tapi puding hilang, ha lepas tu masuk oven, oven pula terbakar, why not korang buat menu ni pula. Yang ni senang gila campur-campur, masuk fridge dah boleh makan. So kita nak buat overnight chia pudding. First, ambil tujuh biji kurma, rendam dalam air. And then korang pergi supermarket, dapatkan Dutch Lady Full Cream milk.\r\nIni perfect untuk buat sahur. Sebab bila kita campurkan kurma semua, minum sekali, dia tahan lama. Ah tak lapar, so kenyang tu lama sikit, seharianlah. Gunakan dua cawan Dutch Lady Full Cream milk tadi, and then letak tujuh biji kurma yang kita dah rendam. Lepas tu korang blend sampailah sebati. Ini akan jadi kita punya base.\r\nSo korang masukkan setengah cawan santan, nak pakai santan kotak pun boleh, tak ada hal. Lepas tu masukkan setengah cawan chia seeds. Chia seeds ni pergi supermarket cari elok-elok, aku risau ada yang beli black pepper nanti, ha nanti panas perut di pagi sahur. So korang rendam overnight lah, lebih kurang satu malam lah. Bila korang nak tidur tu, sahur esok dah boleh makan dah. Actually, sejam dua pun dia dah kembang, rapat sebenarnya.\r\nLepas tu letak dalam mangkuk. And then, yang ini the best part, kita letak kita punya topping. First, kita letak pisang, letakkan peanut butter, lepas tu letakkan chocolate chips. Ini my favorite, sangat sedap. Rasa dia yang, and then tambahkan hirisan kurma pun boleh, letakkan kekacang, and tambahkan madu, look at the... look at that... cantik dia punya warna tu.\r\nKetiga, kita letakkan buah biskut sikit, lepas tu chocolate hazelnut. Ini lebih ke arah dessert-dessert sikit lah tapi still sedap, okay. Seterusnya kita letak buah naga, blueberry, lepas tu letakkan maple syrup dekat atas. Kalau tak jumpa, letakkan madu pun boleh.\r\nAnd last sekali kita buat macam apple pie, kita letakkan epal hijau, letak cinnamon sikit, lepas tu letak granola sikit. Settle. Ini baru lima flavor, banyak lagi boleh buat sebenarnya. Lepas tu campak-campak dah boleh makan, tak perlu masak, tak perlu kukus, tak perlu panggang, tak perlu minyak masak, and everything. Tolonglah, yang ni janganlah fail. Ini dah paling senang dah aku bagi ni, okay. So boleh buat untuk sahur dengan famili nanti. Rasa dia creamy susu, santan, and then kita makan kurma kat dalam, so manis dia just nice lah. So boleh buat try untuk sahur nanti, and makan kenyang-kenyang. Selamat mencuba.'),
(24, 24, 24, 'DVStUQ1k7WX.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DVStUQ1k7WX.txt', NULL, NULL, 'txt', 1, 'B032410624', 'HANIS ALYSHA BINTI RAHAMI', '2026-07-01 21:29:37', 'Hey what\'s up guys, hari ni kan weekend, so jom kita buat siakap stim bersantan, sangatlah sedap rasa dia, refreshing, pekat, pedas, masam, boleh makan satu famili. Okay, korang ambil siakap, letakkan dua batang serai kat dalam, hirisan halia, and daun limau purut sikit, lepas tu korang kelar sikit ikan tu, and kita akan stim. Untuk saiz siakap yang KA pakai ni, boleh stim dalam 15 minit lah. So, ikan akan keluar cantik, fresh macam ni. Air stim ikan dalam pinggan tu jangan buang tahu, yang tu korang letak kat tepi dulu, kita nak pakai lepas ni.\r\nSo, ambil lengkuas sebesar ibu jari, halia sebesar ibu jari, akar ketumbar sikit, and then tiga batang serai, dua ulas bawang putih, empat cili padi, and dua tiga helai daun limau purut. Lepas tu korang masukkan satu kotak kecil santan dengan satu cawan air, pastu kita masak. Masak lebih kurang 5 minit, kita nak bagi santan tu pekat sikit and dia punya aromatics tu serap masuk dalam kuah lah. And then baru kita masukkan satu sudu makan sos ikan, and tambahkan seasoning, garam, gula, serbuk perasa secukupnya, baru tambahkan air stim ikan tu tadi.\r\nKacau-kacau, siaplah kita punya kuah. Boleh letak kat atas. Dia macam tomyam putih pun ada, tapi dia dia bagi twist sikit lah. Tapi cuma sebab dia punya halia, semuanya banyak sangat, keluarkan sikit, aku nak plating ni. And the key ingredient kat sini, korang kena letak sos cili Thai ni. Yang ni wajib letak kat atas, dia akan bagi rasa manis, pedas, and balance lah semua rasa dia. And the best part, korang kena perah limau nipis. Lagi masam, lagi sedap. Perah sebiji, dua biji pun dah okay, boleh hirup kuah dia.\r\nSeriously, sedap sangat-sangat resipi ni. Tolonglah buat. Aku tak makan nasi putih pun end up aku hirup macam tu saja, ratah ikan, stim ni pun dah cukup sedap. Boleh try dengan famili, selamat mencuba. Sedapnya. Ada masam, ada manis sos cili Thai, ada pedas, wangi serai, daun limau purut. Aku rasa puas hatilah, sangat puas hati. Okay, selamat berbuka.'),
(25, 25, 25, 'DVVFfYtk2Q6.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DVVFfYtk2Q6.txt', NULL, NULL, 'txt', 1, 'B032410624', 'HANIS ALYSHA BINTI RAHAMI', '2026-07-01 21:29:37', 'Hey what\'s up guys. Adakah korang tertekan sebab banyak menu dessert nak kejar? Jangan risau, tekanan itu takkan berkurang sebab hari ini kita nak buat apple fritters, sangatlah sedap. Mat Saleh suka makan benda ni. Dia crispy, crunchy dekat luar, dalam sangat lembut dengan epal.\r\nSo ambil satu cawan tepung gandum, setengah sudu kecil garam, setengah sudu kecil cinnamon, satu setengah sudu kecil baking powder, tiga sudu makan gula, satu biji telur, and then tambah satu sudu kecil esen vanila, setengah cawan fresh milk (nak pakai full cream pun boleh), and also satu sudu makan butter yang dah lembut. Kacau-kacau, itu je dia punya batter. Senang saja.\r\nEpal, pergi supermarket cari epal hijau ni. Adakah boleh pakai epal merah? Kurang sesuai, kita nak epal hijau juga sebab apa? Dia ada rasa masam-masam tu. So korang potong-potong dalam bentuk kiub, jangan kecil sangat, jangan besar sangat. Kiub tu kita nak ada crunch-crunch bila kita gigit tu. So gaul dengan kita punya batter tadi. Itu saja. Sangat senang, jangan merungut eh, yang ni senang saja.\r\nAnd kita boleh goreng, make sure minyak tu just nice, tak terlalu panas, taklah kurang panas sangat. Korang akan dapat golden brown macam ni kan? Sabar, jangan angkat lagi. Tunggu sikit lagi sampai dia dark brown macam ni, and barulah kita boleh celupkan ke dalam kita punya glaze.\r\nSo korang ambil satu cawan icing sugar, campurkan dengan tiga sudu air. Nampak macam pekat kan? Tak apa, gaul lagi, glaze tu akan cair, and siap kita punya glaze. So boleh celup kat dalam tu, angkat, tada! Cantik, elok rupa dia. Okay, one more time, one more time. Haa cantik. Macam jual kat kedai. So boleh letak kat tepi dulu, icing sugar tu akan mengeras, and dia akan jadi crunchy-crunchy dekat luar, and boleh gigit. Sangatlah sedap rupa dia benda ni, patutlah Mat Saleh suka makan, kan? Ya Allah, sedapnya. Di manakah dikau bersembunyi selama ini wahai apple fritters? So ni isi kat dalam ada epal, and also crunchiness batter kita dekat luar tu. Bismillah.'),
(26, 26, 26, 'DVX5adgE2Vw.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DVX5adgE2Vw.txt', NULL, NULL, 'txt', 1, 'B032410624', 'HANIS ALYSHA BINTI RAHAMI', '2026-07-01 21:29:37', 'Hey what\'s up guys. Aku ni bukan demam ke tak sihat ke, bukan. Cuma aku bangun sahur tadi aku baru perasan tak record lagi voiceover video ni. Ya Allah, lepas tu record lah time bangun sahur ni dengan mamai.\r\nJom kita tumbuk dulu satu sudu kecil black pepper, tiga ulas bawang putih dengan tiga akar ketumbar. Tumbuk sampai lumat macam ni. Ah lupa nak bagi tahu, kita nak buat sup ikan merah. Lepas tu masukkan satu biji bawang merah, serai sebatang yang dipotong panjang. Kenapa dipotong panjang? Jangan tanya dik, tengah mengantuk tak boleh buka mata ni. Lepas tu masukkan air and tambahkan sup bunjut ikan ni, beli kat supermarket.\r\nLepas tu masukkan serbuk perasa, garam, gula, serbuk sup, semualah seasoning dia tu. And tambahkan cili padi enam biji. Kenapa enam? Tak tahu, tumbuk je, letak je. Lepas tu masukkan ikan merah. Kalau tak ada ikan merah, ganti je apa yang ada kat dapur, siakap ke, kembung ke, boleh, asalkan ikan je. Lepas tu letakkan tomato sebiji, lepas tu letak apa lagi eh? Jap, aku recall balik. Oh lupa, kena tumis darat dulu.\r\nHa lepas tu korang tumiskan bawang ros dalam lima biji yang dihiris nipis, and then sekali dengan cili kering. Lepas tu letak kat atas. Barulah cantik kita punya sup tu. Bawang goreng tu yang bagi sedap sebenarnya. Lepas tu letaklah daun sup, perah lada limau bagi masam semua. Dah, dah habis ke video ni? Ya Allah, tak habis lagi, panjang lagi, kena sambung lagi jap, sikit lagi. Okay, lepas tu boleh makan dengan nasi putih, ha. Nasi putih pun aku kena remind juga cara nak makan? Letak je atas nasi, ha boleh makan sekali sup, and sedia untuk dihidang. Boleh semua, pelajar? Terima kasih. Cikgu nak tidur jap eh. Selamat mencuba. Dah eh, kena bagi masam-masam, pedas-pedas, rasa ketumbar, daun sup semua sedap. Boleh try kat rumah, selamat berbuka.'),
(27, 27, 27, 'DVaU-rZk-Bd.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DVaU-rZk-Bd.txt', NULL, NULL, 'txt', 1, 'B032410624', 'HANIS ALYSHA BINTI RAHAMI', '2026-07-01 21:29:37', 'Ini adalah resipi chocolate mousse versi instant yang memerlukan empat bahan. Tiga bahan korang boleh beli kat kedai, lagi satu bahan korang takkan boleh beli walaupun ada duit sebanyak mana sekali pun. Bahan ni KA ada share dekat hujung video ni.\r\nPertama, korang panaskan setengah cawan cooking cream. Jangan sampai mendidih tahu, cukup sekadar panas saja, and padamkan api. And then korang masukkan dua cawan chocolate chips, lepas tu cream yang panas tadi dia akan cairkan chocolate ni lah. Kalau korang ada mangkuk kaca yang boleh buat double boil, boleh buat cara tu. Kalau tak ada, tak apa, guna je method ni, kita adapt dengan apa yang ada lah.\r\nLepas tu korang ambil satu kotak kecil whipping cream yang sejuk, korang whisk sampai dia kembang, and then kita gaulkan dengan chocolate tadi. And make sure chocolate tadi sejuk baru kita gaulkan tahu. Lepas tu boleh letak dalam cawan, boleh simpan dalam peti sejuk, and boleh makan after a few hours.\r\nTapi kan tadi KA ada cakap ada empat bahan, tapi dah siap masak ni, apa lagi bahan keempat? Bahan keempat tu sebenarnya adalah... effort kita semua untuk mencuba. Video masak yang dibuat ni bukannya standard profesional, bukan untuk dijual kat restoran, dan bukan untuk orang yang ada akses kepada bahan dan kelengkapan level industri. Tapi sebenarnya dia dibuat cukup untuk korang create moment dekat rumah.\r\nAda yang jadikan resipi tu kenangan dengan anak-anak sebelum dorang mula membesar, ada yang guna peluang ni untuk masak bersama famili sebab nak berkumpul ramai-ramai bukannya senang, ada yang masih bujang yang masih baru nak belajar, ada juga yang buat semua ni sebab nak bina kenangan dengan kawan masing-masing. Jadi resipi ni bukan dicipta untuk jadi sempurna, tapi cukup untuk korang luangkan masa dengan famili.\r\nAda yang tak cukup bahan, ada tak cukup ilmu, ada tak cukup kelengkapan, tapi tak apa, kita buat dengan apa saja yang ada. Yang penting kita kena mula cuba. Kalau nak pakai imaginasi sekali pun tak apa, buat, tak ada masalah. Kalau korang fail masak sekali pun, it\'s okay. At least you tried. Kalau kita letak minda yang memasak itu susah, kena sempurna, macam mana kita nak tarik anak muda untuk masuk ke dapur ni? Mungkin dari sini dorang belajar berdikari, belajar buat silap, and belajar berinovasi.\r\nDalam hidup ni, kita jangan tengok dunia kita saja, kita kena jenguk juga situasi kehidupan orang lain kat luar sana. Dan dari situlah kita akan mula wujud kesafahaman, and bila kita faham satu sama lain, dari situlah rasa empati akan wujud sesama kita. Dengan apa yang terjadi di seluruh dunia sekarang ni, memang impossible, tidak dapat kita selesaikan dengan video masak simple macam ni. Tapi at least, sekurang-kurangnya kita dapat satukan semua walaupun video itu hanya seminit dua sahaja.'),
(28, 28, 28, 'DVadgrRk1Nw.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DVadgrRk1Nw.txt', NULL, NULL, 'txt', 1, 'B032410624', 'HANIS ALYSHA BINTI RAHAMI', '2026-07-01 21:29:37', 'Hey what\'s up guys. Sebenarnya aku baru perasan, selepas 9 tahun buat video masak, aku tak pernah guna sebenarnya petai dengan tempoyak. Hari ni first time. Kesian kat korang, tak grad silibus lagi. Petai dengan tempoyak tak pernah guna lagi. Hari ni kita guna, kita nak buat udang masak tempoyak petai.\r\nSo korang ambil udang, gaul dengan garam dengan kunyit, lepas tu goreng sampai golden brown macam ni, boleh angkatlah. And then ambil empat lada besar, lapan cili padi, satu bawang merah, dengan lima ulas bawang putih. Yang ni mungkin korang macam perasan, \"Eh, asyik chop benda sama je, bosan gila.\" Senang, bapak bahan ni paling senang ada kat rumah.\r\nOkay, lepas tu korang tambahkan satu batang serai, tambahkan serbuk kunyit sikit, lepas tu sambung tumis. And masukkan satu per tiga kotak kecil santan, tak perlu banyak-banyak, kita just nice macam ni saja. Tambahkan air sikit, lepas tu masukkan dalam dua helai daun limau purut, setengah kiub pati ayam, lepas tu korang tambahkan garam dulu secukup rasanyalah. Lepas tu kacau kacau kacau, ini baru kita tambahkan lebih kurang satu atau dua sudu tempoyak. Walaupun menu dia nama tempoyak, kalau korang tak ada tempoyak apa-apa, boleh skip tak ada masalah lah. Yang ni letak satu sudu atau dua sudu pun tak apa. And tumis sampai dia pecah minyak.\r\nMacam ni baru korang masukkan udang yang kita goreng tadi. And last sekali, petai. Ha taburlah dekat atas, and dah siaplah kita punya masakan. Nak buat yang berkuah sikit, boleh lebihkan air, nak yang buat pekat macam ni pun boleh juga. And letaklah dalam pinggan, susun elok-elok cantik macam ni, ala... macam menu kat Rembau. Selamat datang ke Rembau. Tapi lagipun aku tak jual benda ni, korang kena masak sendiri kat rumah. Selamat mencuba. Belum habis lagi video, sikit lagi.'),
(29, 29, 29, 'DVdChjGE-Nu.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DVdChjGE-Nu.txt', NULL, NULL, 'txt', 1, 'B032410624', 'HANIS ALYSHA BINTI RAHAMI', '2026-07-01 21:29:37', 'Hey what\'s up guys, aktiviti berkumpulan kembali lagi. Hari ni kita nak buat menu yang sangat simple, sangat senang tapi dia banyak komponen sikit. Haa korang boleh buat satu famili ataupun dengan kawan-kawan. Yang kita nak buat tahu sumbat crispy, sangatlah sedap.\r\nSo korang ambil tahu keras ni, beli kat supermarket. Beli yang keras, bukannya yang lembut. Sebab yang lembut tu, kau sentuh sikit pun dah lerai dah. So tahu keras ni kita potong diagonal bagi bentuk segi tiga macam ni. Ambil dua sudu tepung beras, dua sudu tepung Bestari, garam sikit, dengan setengah cawan air. Kita kacau kacau kacau, and then korang masukkan kita punya tahu tadi bagi dia berendam. Bagi dia berehat dalam tu, letak kat tepi.\r\nUntuk sos, ambil lima ulas bawang putih, tiga sudu makan cili kisar yang KA pakai ni yang cili tak pedas lah, satu per tiga cawan sos cili Thai, setengah sudu makan tepung jagung, dan tiga cawan air. Air tu memang nampak banyak, tapi tak apa, kita blend je, and kita masak, okay. Sebab apa air banyak? Sebab kita nak masak lama sikit. And korang masukkan dua ketul kecil gula Melaka ni, and masaklah. Masak sampai air tu mulai kering sikit, and kuah mula pekat, baru kita masukkan garam dengan secukup rasa. And siap kita punya kuah. Bila sejuk, dia akan lagi pekat lagilah nanti.\r\nOkay next, kita goreng yang kita punya tahu tadi tu. Kalau nak senang, korang boleh stop goreng kat sini bila dah golden brown. Kalau nak extra, air tepung tadi jangan buang. Kita tabur dekat atas, make sure minyak betul-betul panas. And bila korang dah renjis-renjis kat atas tu, jangan usik. Ah no, no, no, jangan sentuh. Biar je macam tu. Tak apa dia melekat pun, biar dia betul-betul crispy sebab once dia dah crispy, korang boleh leraikan dia balik. Ah jangan risau. Okay dah siap, boleh angkat. Ah dengar dia punya crispiness kat situ tu.\r\nAh okay next, kita nak buat dia punya topping kat dalam tu, senang saja. Korang sagat-sagat kan carrot, ah boleh tambah sengkuang kalau nak, timun batang. And bila kita sagat ni, dia akan berair sikit tahu, so kita kena kering-keringkan sikit dia punya air tu. Jangan lupa taugeh kena ada juga. Haa kepada yang tak minat taugeh, minta maaf. Taugeh sangat sedap, aku suka taugeh.\r\nAlright, so kita boleh potong kita punya tahu tu dekat tengah, sumbat kita punya inti kat dalam. Dah nama pun tahu sumbat, so kenalah sumbat kat dalam. As simple as that, itu saja. Yang korang boleh buat banyak-banyak, hidang satu famili. Rasa dia sangat sedap, crispy kat luar, lembut dekat dalam. So nanti balik rumah malam ni bolehlah buat. ASMR. (Crunch sounds). Sedapnya. So bolehlah try buat, selamat mencuba.\r\n'),
(30, 30, 30, 'DVfZw9KkwWp.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DVfZw9KkwWp.txt', NULL, NULL, 'txt', 1, 'B032410624', 'HANIS ALYSHA BINTI RAHAMI', '2026-07-01 21:29:37', 'Hey, what\'s up guys. Nak tahu hari ni kita buat pretzels yang korang beli dekat mall tu, tapi boleh buat sendiri kat rumah sebenarnya, sangat senang. Pakai lima enam bahan yang dalam almari, bawa keluar sekarang, so jom kita start.\r\nFirst, korang ambil satu cawan air, tambahkan lagi satu perempat cawan air. So total satu satu perempatlah. Masukkan satu sudu makan yeast, dan juga satu perempat cawan brown sugar. Kalau tak ada, gula putih pun boleh, barulah gaulkan dengan empat cawan tepung gandum. Kalau macam kering sangat, tambahkan satu atau dua sudu air. Uli sampai dia tak melekat dah. Memang doh dia padat, jangan risau. Bagi dia kembangkan dekat luar lebih kurang setengah jam, barulah kita bentukkan dia.\r\nYang ni, potong pakai pisau je dik, senang. Tak perlu nak pakai equipment pelik-pelik ke apa, tak payah. Panjangkan bentuk dia. Nak buat bentuk reben macam orang jual dekat kedai pun boleh, ataupun pemalas macam KA, potong kiub-kiub macam tu pun dah cantik. Tapi nak lagi extra, kita panjangkan sikit doh tu, kita balut dekat sosej. Carilah sosej yang dalam freezer yang mana ada.\r\nAmbil satu cawan air, campurkan dengan satu sudu makan soda bikarbonat, and kita mandikan kita punya doh tadi kat dalam. Okay, tujuan dia, kita nak bagi doh kita tu chewy dekat luar, tapi lembut kat dalam. Yang hot dog tu pun sama, korang mandikan dia sekejap, letak atas tray, and bakar pada suhu... eh sebelum tu letak garam dulu. Haa kita boleh letak garam kasar. Kalau tak ada, pakai garam biasa pun boleh, tapi jangan banyak sangat, takut masin.\r\nSo bakar pada suhu 250°C selama 5 minit sahaja. Yes, api dia memang besar sebab tu bakar sekejap sahaja. And salutkan dengan melted butter. And siaplah kita punya pretzels ni, berkilat, elok, cantik rupa dia, boleh makan panas-panas. Disebabkan dia ada rasa masin-masin kat hujung tu, kalau korang cicah dengan chocolate hazelnut, sangatlah perfect.\r\nAtaupun nak extra, ni favorite KA, yang berbalut hot dog ni, korang boleh cicah dengan cheese sauce. Yang tu simple je, korang cairkan dua tiga keping cheese cheddar yang keping, dengan sedikit cooking cream lah, and dah siaplah kita punya cheese sauce. Sedapnya, sedapnya, sejak bila aku pandai buat pretzel ni? Yang rasa garam tu yang bagi punch dekat kita punya pretzel ni, tapi doh dia, luar chewy dalam lembut. Okay, selamat mencuba.'),
(31, 31, 31, 'BjwCaApn2XS.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/BjwCaApn2XS.txt', NULL, NULL, 'txt', 1, 'B032410531', 'MUHAMMAD HAZIQ BIN MOHAMAD ZAKI', '2026-07-01 08:41:37', 'Hey what\'s up guys, so hari ni kita nak buat popia carbonara. Makanan ni hipster sikitlah, tapi rasa dia sedap. Jom kita start.\nOkay, first kita goreng satu biji bawang besar, kemudian tambahkan isi ayam yang dah dicincang, tiga batang sosej, satu botol sos carbonara, sedikit air, satu batang carrot, dan juga sedikit black pepper.\nItu saja inti dia, bagi dia sejuk dulu. Kemudian kita ambil cheese, potong dua, kemudian kita letakkan inti tadi dalam kulit popia, letakkan cheese, kemudian balut.\nIni kalau korang tanya, \"Bukan semalam dah buat popia nestum ke?\", ya kulit popia aku ada lebih, so aku nak gunalah ni.\nOkay, goreng goreng goreng. Kemudian kita goreng. Time ni rupa dia okay lagi, and then... surprise! (burned/burnt). Tapi tak apa, rasa dia sedap, serius sedap gila.\nLagipun tak apa, orang Malaysia kan suka makan cheese. Dia macam yang keluar berita semalam lah.\n\"Mak cik, kenapa mak cik suka makan cheese ya?\"\n\"Mak, mak tak boleh kalau makan nasi kerabu tak ada cheese. Mak, mak kena makan budu dengan cheese. Mak, mak cannot, mak cannot.\"'),
(32, 32, 32, 'Bjy4yyPFac0.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/Bjy4yyPFac0.txt', NULL, NULL, 'txt', 1, 'B032410531', 'MUHAMMAD HAZIQ BIN MOHAMAD ZAKI', '2026-07-01 08:41:37', 'Hey what\'s up guys, so hari ni kita nak buat pizza cara bujang. Rasa dia sedap, jom kita start.\r\nFirst kita letakkan sos pasta ke atas roti.\r\nKemudian tambahkan bawang merah,\r\nand then mozzarella cheese.\r\nLepas tu letakkan bell pepper, hot dog. Hot dog ni korang goreng dululah.\r\nKemudian tambah lagi cheese, kemudian letakkan roti.\r\nAnd then kita sapukan butter dekat atas. Butter ni letak banyak sikitlah baru dia crispy.\r\nKemudian kita goreng. Yang ni korang terbalikkan sandwich ni, biarkan yang butter tu dekat bawah.\r\nAnd then sapu butter dekat atas pula, lepas tu baru flip.\r\nTu dia! Make sure tutup sebab kita nak bagi cheese tu cair.\r\nAlright, tu je lah. Dah siap, and then potonglah.\r\nBiasanya budak-budak suka makan menu macam ni. Jap, aku tanya anak aku.\r\n\"Johnny, Johnny?\" (Yes, Papa)\r\n\"Sedap tak Papa masak?\" (No, Papa)\r\n\"Dah tu kau nak makan ke tak?\" (No, Papa)\r\nKurang asam punya anak! Haha.'),
(33, 33, 33, 'Bj1dMtilcOo.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/Bj1dMtilcOo.txt', NULL, NULL, 'txt', 1, 'B032410531', 'MUHAMMAD HAZIQ BIN MOHAMAD ZAKI', '2026-07-01 08:41:37', 'Hey what\'s up guys, so hari ni kita nak buat cornflakes madu. Rasa dia crispy, manis, sedap. Jom kita start.\r\nFirst kita cairkan satu per empat block butter, kemudian tambahkan satu per empat cawan brown sugar.\r\nKacau-kacau-kacau, and then tambahkan tiga per empat cawan madu.\r\nKacau lagi sampai dia berbuih macam ni.\r\nAnd then kita gunakan 250 gram cornflakes.\r\nKorang tuangkan sos yang kita dah buat tadi, gaulkan sampai dia rata.\r\nKemudian kita letakkan dalam cup yang kecil-kecil macam ni, dan tambahkan sedikit sesame seeds (bijan). Yang ni tak wajiblah, kalau nak bolehlah.\r\nKemudian bakar pada suhu 150°C selama 7 minit.\r\nDan biarkan dia sejuk kejap, and ready untuk dihidang.\r\nBila sebut madu ni, teringat kat jiran aku. Aku lupa dah apa nama dia, hm...\r\n\"Encik Jamil yang kahwin ya?\"\r\n\"Ha\'ah Jamil, macam mana akak boleh kenal?\"\r\n\"Ya, memang saya izinkan Jamil kahwin.\"\r\n\"Lah, baguslah akak ni.\"\r\n\"Siylah kau punya Jamil!\"\r\n\"Habislah kau Jamil!\"'),
(34, 34, 34, 'Bj3x-rtFt5v.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/Bj3x-rtFt5v.txt', NULL, NULL, 'txt', 1, 'B032410531', 'MUHAMMAD HAZIQ BIN MOHAMAD ZAKI', '2026-07-01 08:41:37', 'Hey what\'s up guys, so hari ni kita nak buat lala masak pedas, jom kita start.\r\nOkay first kita gunakan tiga ulas bawang putih, satu inci halia, satu biji bawang merah, dan juga dua batang serai.\r\nKemudian kita masukkan satu sudu cili boh, kacau, and then masukkan dua sudu sos cili, dua sudu sos tiram, and sedikit air.\r\nKita masukkan gula dan juga garam, secukup rasa.\r\nKemudian masukkan cili dan daun limau purut.\r\nAkhir sekali korang masukkan lala dan kacau.\r\nYang ni tak payah lama pun sebab seafood sekejap je masak. Kalau dia dah terkangkang tu dah masak dah tu lah. Okay, alright.\r\nSo lala kita dah sedia untuk dihidang, tapi sebelum tu... DJ Minmin!\r\n\"Ya dik?\"\r\n\"Nak lagu untuk lala, please!\"\r\n\"Boleh dik, dengarkan... Lala...\"\r\n(Singing: \"Lala... lala... lala...\")'),
(35, 35, 35, 'BkeW1ion6FV.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/BkeW1ion6FV.txt', NULL, NULL, 'txt', 1, 'B032410531', 'MUHAMMAD HAZIQ BIN MOHAMAD ZAKI', '2026-07-01 08:41:37', 'Hey what\'s up guys, so hari ni kita nak buat healthy tuna sandwich. Jom kita start.\r\nFirst kita hancurkan dua biji telur rebus, and then tambahkan satu tin tuna.\r\n(Cat meows: \"Meow\")\r\nHa, dia datang dah.\r\n(Cat meows: \"Meow\")\r\nJangan menyibuk dekat sini! Kucing aku ni pantang sikit bau tuna.\r\nOkay, gaulkan dengan telur tadi, kemudian kita tambahkan satu sudu mayonis, dan juga setengah biji tomato, dan juga sedikit bawang merah.\r\nOkay, and then tambahkan sedikit black pepper dan juga sedikit garam, and akhir sekali, separuh biji lemon.\r\nAlright, kemudian gunakan whole wheat bread, tambahkan sayur, and then letakkan dalam dua layer macam ni.\r\nKemudian kita potong. Nak potong dua boleh, nak potong empat pun boleh.\r\nNi kalau kau makan telur rebus, kalau kentut busuk jangan tak mengaku pula.\r\n\"Siapa yang kentut busuk ni? Farhana?\" (Eh tak, bukan saya)\r\n\"Mengaku je lah Farhana, kau seorang je yang kentut busuk kat sini.\"\r\n(Eh tak, ya Allah tak!)'),
(36, 36, 36, 'Bkg5O-ynSdq.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/Bkg5O-ynSdq.txt', NULL, NULL, 'txt', 1, 'B032410531', 'MUHAMMAD HAZIQ BIN MOHAMAD ZAKI', '2026-07-01 08:41:37', 'Hey what\'s up guys, so hari ni kita nak buat chicken teriyaki yang aku rasa macam ayam kicap. Jom kita start.\r\nFirst kita gorengkan ayam dengan olive oil, kemudian tambahkan sedikit garam, and bagi dia garing sikit.\r\nKemudian kita tambahkan satu inci halia dan juga dua ulas bawang putih yang dah dicincang.\r\nKemudian tambahkan dua sudu kicap dan juga satu sudu madu.\r\nKemudian tambahkan satu biji bawang besar, and akhir sekali masukkan sedikit air tepung jagung.\r\nKacau sampailah kuah dia pekat.\r\nOkay, untuk sayur pula, kita akan rebuskan sedikit brokoli, and akhir sekali kita hidang dengan brown rice.\r\nTapi makan sihat saja tak cukuplah, kenalah bersenam juga.\r\n\"Mama kan suka bersantai, tapi kenapa kali ni nak bersenam pula?\"\r\n\"Tak tahu lah Chal. Mama rasa peha Mama makin besar. Kau rasa badan Mama makin berat tak?\"\r\n\"Ha\'ah, beratnya!\"\r\n\"Kau cakap apa?\"\r\n\"Eh tak ada apa-apa lah, uuu~\"\r\n\"Awas kau!\"'),
(37, 37, 37, 'BktzM_2n9Cl.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/BktzM_2n9Cl.txt', NULL, NULL, 'txt', 1, 'B032410531', 'MUHAMMAD HAZIQ BIN MOHAMAD ZAKI', '2026-07-01 08:41:37', 'Hey what\'s up guys, so hari ni kita nak buat chicken with black pepper mushroom. Resipi ni tak adalah sihat sangat, tapi sedap. Jom kita start.\r\nFirst kita gaulkan ayam dengan garam dan juga black pepper.\r\nKemudian kita goreng sampailah dia garing dan juga crispy macam ni.\r\nBuangkan sedikit minyak yang dah diguna tadi, and then tambahkan button mushroom yang dah di-slice.\r\nKemudian kita tambahkan sedikit garam, and then kacau lagi sampailah dia layu dan brown.\r\nKemudian kita tambahkan dua ulas bawang putih yang dah dicincang, and then sedikit butter, dan juga sedikit air.\r\nKemudian tambahkan satu sudu sos black pepper.\r\nKacau kacau kacau sampailah dia pekat, and sedia untuk dihidang.\r\nResipi ni sebenarnya sesuai kalau korang nak buat untuk anniversary.\r\n\"Abe, today me prepared chicken mushroom for our one week anniversary.\"\r\n\"Tapi, Abe... Abe cannot eat chicken. Selsema lah baby, allergy.\"\r\n\"Allergy?!\"\r\n\"Really Abe, really?!\"'),
(38, 38, 38, 'Bk_0vW3nKqr.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/Bk_0vW3nKqr.txt', NULL, NULL, 'txt', 1, 'B032410531', 'MUHAMMAD HAZIQ BIN MOHAMAD ZAKI', '2026-07-01 08:41:37', 'Hey what\'s up guys, so hari ni kita nak buat ikan bakar dengan air asam. Jom kita start.\nFirst kita hancurkan sedikit belacan yang dah dibakar. Kemudian tambahkan satu biji bawang merah,\nsatu biji tomato, lima biji cili, dan juga setengah cawan air asam jawa.\nOkay, kacau kacau kacau, kemudian tambahkan sedikit garam, setengah sudu gula, dan juga satu per empat biji limau nipis.\nOkay, dah siap air asam. Untuk ikan pula, kita bakarkan ikan kembung. Yang ni aku bakar kosong je, tak ada letak garam, tak ada letak apa-apa.\nTapi kalau korang nak lagi sedap, bakarlah ke atas api. Bakar dalam oven ni dia tak rasa smoky sangat.\nTapi overall best lah. Ikan ni aku bakar banyak-banyak, yang lain semua boleh makan, rupa-rupanya kucing aku yang telan.\nDahlah gemuk, suka tidur, lepas tu makan pula banyak.\n(Music / singing in background: \"I got no...\")'),
(39, 39, 39, 'BlHlXhylVPy.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/BlHlXhylVPy.txt', NULL, NULL, 'txt', 1, 'B032410531', 'MUHAMMAD HAZIQ BIN MOHAMAD ZAKI', '2026-07-01 08:41:37', 'Hey what\'s up guys, so hari ni kita nak buat overnight oatmeal yang sihat, jom kita start.\r\nFirst kita perlukan tiga per empat cawan oats, setengah cawan plain yogurt, setengah sudu madu, dan juga satu cawan susu segar.\r\nKacau, kemudian letakkan dalam peti sejuk selama satu malam.\r\nKemudian bangun esok pagi, korang boleh letak toppings yang korang sukalah. Nak letak buah naga boleh, kalau nak rasa tropical boleh letak mango.\r\nAnd kalau rasa crunchy-crunchy macam tu boleh tambahkan pistachio dan juga kurma.\r\nAnd kalau rasa nak western sikit, letaklah pisang dan juga chocolate chips.\r\nResipi oatmeal ni sesuailah kalau korang nak buat breakfast, ataupun kalau macam tersedar tidur tengah malam lepas tu lapar ke...\r\n\"Bang, soalan!\"\r\n\"Apa dia dahlah malam-malam tanya soalan...\"\r\n\"Ni pukul berapa ni... Kenapa aku rasa lapar nak makan? Makanan tak ada ni...\"\r\n\"Eh, oats kan ada. Selamat aku buat oats semalam.\"'),
(40, 40, 40, 'BlpCTB7HJ0o.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/BlpCTB7HJ0o.txt', NULL, NULL, 'txt', 1, 'B032410531', 'MUHAMMAD HAZIQ BIN MOHAMAD ZAKI', '2026-07-01 08:41:37', 'Hey what\'s up guys, so hari ni kita nak buat resipi kentang putar, jom kita start.\r\nFirst kita cairkan satu setengah sudu butter, kemudian kita gorengkan satu biji bawang besar, dan tambahkan satu setengah sudu tepung gandum.\r\nBagi dia garing, kemudian tambahkan satu cawan air.\r\nKemudian kita blend-kan adunan ni, masukkan kembali dalam kuali, kemudian tambahkan setengah kiub pati ayam, dua sudu besar sos lada hitam, dan juga sedikit garam.\r\nOkay kacau, sos pun dah siap. Ah laju resipi ni.\r\nOkay next, kita rebuskan ubi kentang ni, rebus sampai empuk, kemudian lenyekkan dengan garfu,\r\ndan tambahkan setengah sudu butter, satu per empat cawan susu segar, sedikit black pepper, dan juga sedikit garam.\r\nOkay dah siap. Okay, aku nak muzik dramatik. Mana cepat-cepat!'),
(41, 41, 41, 'DVAa0SPk_YG.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DVAa0SPk_YG.txt', NULL, NULL, 'txt', 1, 'B032510782', 'ALEEYA MELISSA BINTI ABDULLAH', '2026-07-01 08:41:37', 'Hei, what\'s up guys, so semua resipi malam anda dah buat kan?\nSebab hari ini kita nak switch pergi ke international studies.\nKita nak buat ayam peri-peri. Sangat senang guna air fryer saja.\nJadi ambil 2 lada benggala, 2 bawang merah, 5 ulas bawang putih, 5 cili padi.\nKorang potong kasar, gaul dengan minyak masak.\nDan kita bakar dalam air fryer pada suhu 200 celsius selama 20 minit.\nDia akan keluar garing macam inilah.\nLepas itu, letak semua dalam blender.\nPerah separuh biji lemon. Masukkan satu suhu makan oregano.\nYang ini boleh cari dekat bahagian spices.\nDan masukkan satu sudut kecil garam.\nSetengah cawan minyak masak.\nSegenggam kecil daun ketumbar.\nDan tambahkan satu sudut kecil gula.\nLepas itu kita blend. Simple sahaja, dapatlah kita punya peri-peri sauce.\nUntuk ayam pula.\nKejap mana ayam ni? Cepat.\nAyam ni, kau dah letakkan garam sikit.\nLepas itu, korang dah masukkan sikit sauce yang kita dah buat tadi tu.\nMake sure dia rata, rapi semua.\nPerap 20 minit, baru kita bakar.\nSama macam suhu tadi, 200 celsius juga selama 20 minit.\nJadi daripada buat sauce,\nPerap dan bakar, total lebih kurang sejam lah. Senang sahaja.\nUntuk sauce dia pula, ambil lebihan barang blend tadi.\nKau dah tambahkan satu sudut butter.\nPanas ke atas kuali sekejap. Siaplah.\nDia punya sauce. Sangat simple. Sangat senang boleh try.\nYang mana masih buat ayam sauce plum tu?\nPlease, please. You guys dah sangat-sangat behind ke belakang.\nSo please keep up.\nTry buat ayam ni pula hari ni.\nSo boleh try. Makan dengan family.\nSangatlah sedap rasa dia. Selamat mencuba.\n\n'),
(42, 42, 42, 'DU-RHvxkwy4.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DU-RHvxkwy4.txt', NULL, NULL, 'txt', 1, 'B032510782', 'ALEEYA MELISSA BINTI ABDULLAH', '2026-07-01 08:41:37', 'Hei, what\'s up guys. Kamu dah balik dari supermarket ke?\nJom kita pergi lagi sekali untuk beli roti mantau\ndan cicah dengan buttermilk sauce yang sangat sedap.\nOkay, first ambil 4 ulas bawang putih, 3 cili padi kita chop chop chop\nlepas tu kita tumis dengan 1 sudu butter.\nTumis tak perlu lama sangat, tunggu dia layu sikit saja\ndan dia masukkan 2 tangkai daun kari.\nKacau tumis lagi lepas tu kita tambahkan setengah tin susu cair\ndan dia kita masukkan sikit cube pati ayam.\nJangan banyak sangat tau, nanti dia terlebih masing.\nTambah setengah susu pekat manis dengan 2 keping cheese.\nLepas tu pergi supermarket cari roti mantau mini ni\ndekat bahagian frozen.\nDia macam marshmallow tapi ini bukan marshmallow.\nAku risau salah beli nanti.\nRoti mantau, cari dekat bahagian frozen.\nGoreng sampai golden Brown macam ni.\nDan sedia untuk dihidang, nampak dia punya plating.\nCantik saja, senang semua dalam tray ni.\nBoleh makan panas panas, cicah, cicah pula.\nCicah dengan buttermilk sauce kita.\nYang ni senang saja.\nYang mana, yang muda-muda genZ kat rumah yang KA saya tak nak resipi susah.\nIni paling simple lah ni.\nBoleh buat dan hidang makan dengan family nanti.\nSelamat mencuba.\nDia simple je, cicah kuah macam ni je.\nTapi rasa dia sangat lah ngam.\nBerpeluh aku ni spec.\n'),
(43, 43, 43, 'DGxDbMrv_xe.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DGxDbMrv_xe.txt', NULL, NULL, 'txt', 1, 'B032510782', 'ALEEYA MELISSA BINTI ABDULLAH', '2026-07-01 08:41:37', 'Hey what\'s up guys, so hari ni kita nak buat hot chicken tenders yang dimakan dengan creamy white sauce\nSangatlah sedap. Okay first, korang ambil tepung bestari, splitkan dua\nSatu bahagian tu korang campurkan dengan air bagi dibasah\nDan dia celupkan dengan kita punya isi ayam yang potong panjang-panjang lah\nLepas tu ambil ayam tu celup dengan tepung bahagian kering dan kita boleh goreng\nMake sure minyak betul-betul panas, goreng sampai dia jadi crispy golden brown macam ni\nSo sementara tunggu ayam tu siap masak, kita nak prepare dia punya spices lah\nSaya ambil satu sudu serbuk paprika, satu sudu cayenne pepper\nAnd then tambahkan setengah sudu garlic powder and also setengah sudu cili flakes\nAnd then tambahkan garam secukupnya dengan satu sudu brown sugar\nLepas tu ambil minyak goreng yang betul-betul panas tadi, tuang ke atas untuk kita masak\nKita punya spices ni dan siap lah kita punya hot oil\nSo ayam tu korang boleh mandikan dengan minyak tu\nLepas tu kacau-kacau melekat dia punya spices boleh angkat\nTapi belum siap lagi kita perlukan sauce\nUntuk sauce korang ambil tiga sudu yoghurt yang flavour original ni\nTambahkan tiga sudu kiupy pimeo, perahkan lemak sikit, masukkan black pepper\nMasukkan dua ulas bawang putih yang dah ditumbuk hancur and also garam secukupnya\nKacau-kacau siap kita punya sauce and then boleh celup kat dalam\nPanjang narrationnya, tapi aku dah kecur air liur ni\nIni boleh makan panas-panas, dia tak adalah pedas yang sampai luar kawalan\nPedas dia just nice\nKicap dengan creamy sauce memang dia balance\nAnd surprisingly korang tak perlu buttermilk\nAtau apa boleh buat simple macam ni sahaja dekat rumah\nSelamat mencuba   \n'),
(44, 44, 44, 'DU92oBqE3nx.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DU92oBqE3nx.txt', NULL, NULL, 'txt', 1, 'B032510782', 'ALEEYA MELISSA BINTI ABDULLAH', '2026-07-01 08:41:37', 'Hey, what\'s up guys. So katakan hari ni korang pergi supermarket, sauce plum tak ada. Tak apa, kita switch ke Cantonese Yeemee.\nSangat senang, mudah, beginner friendly nak buat. Korang ambil 4 ulas bawang putih yang dah chop chop, tumis sekejap.\nMasukkan seafood. Yang ni kita guna udang, sotong, tambahkan fish cake sekali.\nLepas tu masukkan air. Yang ni korang tambah satu sudu sauce tiram, tabur-tabur white pepper agak-agak yang ni.\nMasukkan carrots, lalu seasoning lah, garam dan perasa secukupnya.\nYang ni masukkan minyak bijan sikit, sesame oil, dan dah tambahkan sayur.\nLepas tu masukkan air tepung jagung untuk bagi dia pekat. Lepas tu korang pukul telur, jujush-jujush, masukkan ke dalam.\nSimple saja, dan baru letak kita punya yeemee. Yeemee tu korang jangan sentuh, jangan usik, jangan terbalikkan dia.\nBiar macam tu sahaja sekejap, lepas tu dah boleh hidang.\nKita nak biar dia lembut kat bawah, crispy kat atas, tuangkan kita punya kuah yang Cantonese tu.\nLepastu siap lah. Aku habis live lambat semalam, suara aku dah macam ni.\nSebab tu nak makan benda panas, barulah macam lega sikit tekak.\nTapi jangan risau, suara tak ada pun aku tak akan MC.\nKelas tetap berjalan, video tetap akan banyak.\nYeemee ni korang tak boleh masak penuh tau, biarkan dia lembut separuh, keras separuh.\nBaru dia ada kukrak-kukrak bila korang makan.\n'),
(45, 45, 45, 'DU7il32EkxQ.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DU7il32EkxQ.txt', NULL, NULL, 'txt', 1, 'B032510782', 'ALEEYA MELISSA BINTI ABDULLAH', '2026-07-01 08:41:37', 'Hey what\'s up guys, hari ni kita nak buat ayam pop\nYang mana masih buat ayam sauce plum tu, you already behind schedule ni\nKena cepat kena kipap sebab syllabus kita banyak tahun ni\nSo ayam tu korang masukkan 4 batang serai yang dah diketuk\nHalia sebesar ibu jari dengan 15 bawang putih yang diketuk juga\nAnd then ni ada orang jual tepi jalan ataupun dekat baza lah\nAir kelapa korang gunakan 3 cawan sahaja\nIsi dia tak nak air dia sahaja\nMasukkan 1 per 4 cawan santan\nAnd then 1 sudu kecil garam\nLepas tu kita didihkanlah ayam tersebut\nSo ambil 1 biji tomato\n15 biji cili padi\n1 biji bawang merah\n15 bawang putih dengan seketul belacan yang dah dibakar\nSo ini kita blend guna minyak tak guna air sebab tak nak dia merecek sana sini lah\nLepas tu masukkan 2 helai daun limau purut yang dah dipotong\nBila dah kering baru korang masukkan air\nDan tambahkan dalam 2-3 sudu santan\nBila dia color dah cantik, dah helok macam ni\nBaru korang masukkan seasoning lah, garam gula sebut perasa secukupnya\nSambung tumis lagi sampai dia pecah minyak dan berkilat macam ni\nUntuk ayam tadi korang kena terbalik-balikkan dia selalu tahu kalau tak pecah santan nanti\nSo ayam dah masak, keluarkan\nKeluarkan serai, halia semua tu bagi kosong kat dalam\nTinggal air dia sahaja\nTambahkan setengah kotak kecil santan\nTambahkan gula sikit\nAnd also air tepung jagung sikit dan bagi dia pekat lah\nDan siap lah kita punya kuah\nAnd then ni optional\nKalau korang boleh cari pucuk ubi kayu\nBoleh rebuskan sekali dengan garam kalau nak\nKalau tak jumpa tak apalah\nSo boleh makan macam ni\nLetakkan kita punya sambal tadi\nTuangkan kita punya kuah santan kat atas ayam tu\nDan siap lah kita punya ayam pop\nYa menu ni kalau pergi kedai nasi padang\nMemang aku selalu wajib order lah\nKalau tak ratah macam tu\nKita makan dengan nasi putih\nSedap\n'),
(46, 46, 46, 'DHArkFpPasu.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DHArkFpPasu.txt', NULL, NULL, 'txt', 1, 'B032510782', 'ALEEYA MELISSA BINTI ABDULLAH', '2026-07-01 08:41:37', ' Hey what\'s up guys, so siapa kat sini peminat tempe, hari ni kita nak buat tempe goreng crispy\nKukrak-kukrak bunyi dia boleh cincah  dengan sambal kicap pedas ni sangatlah sedap\nSo korang ambil 6 ulas, eh belum lagi, ambil tempe dulu tempe\nKita potong, potong dua, dan potong nipis-nipis\nLagi nipis, lagi crispy lah\nBaru ambil 6 ulas bawang putih\n1 sudu biji ketumbar, separuh kiub pati ayam, separuh biji bawang merah\nDan tambahkan gula lebih kurang 1 sudu kecil\nDan tambahkan garam dengan ajinamoto\nDan tambahkan white pepper\nDan letakkan 1 sudu tepung jagung\nLepas tu tambahkan air\nAir jangan banyak sangat\nSebab kita nak kita punya perapan ni dia tak cair sangat, tak pekat sangat lah\nLebih kurang macam ni rupa dia\nAmbil tempe tadi, celup kat dalam\nLepas tu boleh angkat dan goreng dalam minyak panas\nSo perapan kita tu dah ada rasa masin-masin balance lah\nSo just nice\nBila dah nak garing, korang masukkan bawang putih yang belum dikupas\nDan boleh angkat sekali bila dah masak semuanya lah\nTapi bila lagi kita nak buat dia punya sambal kicap pula\nSenang je, korang blendkan kicap manis\nCili padi dengan bawang putih, sampai lumat\nDan sekarang dah boleh serve\nDengar tak bunyi dia tu, kruk-krak kruk-krak\nCicang dengan sambal kicap pedas sangat sedap\nBiasa orang makan benda ni waktu petang\nTapi bulan puasa jangan lagi, puasa dulu malam nanti baru buat\nSo korang boleh try dekat rumah\nSelamat mencuba\n'),
(47, 47, 47, 'DHc62H8yNbB.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DHc62H8yNbB.txt', NULL, NULL, 'txt', 1, 'B032510782', 'ALEEYA MELISSA BINTI ABDULLAH', '2026-07-01 08:41:37', 'Kepada pelajar-pelajar, cikgu penat, hari ni suara ku sengau sebab dah habis demam lah selsema pula, jadi aku pakailah filter ni, ingat korang je ke boleh pakai, aku boleh pakai juga\ntapi hari ni kita penat sebab tak cukup tidur, jadi kita nak buat resepi simple saja, iaitu ayam goreng masak lemak cili api, yang ni dah ramai orang buat sebenarnya tapi kita mengidam wak, jadi kita buat lah\nso senang saja korang ambil ayam goreng, gaulkan dengan garam dan serbuk kunyit, gaul-gaul-gaul, lepas tu kita goreng, part goreng ayam goreng ni aku rasa semua dah mahir lah kot, boleh angkat ke tepi\nlepas tu korang ambil 1 bawang merah, 8 cili padi dengan 13 ulas bawang putih, nak cop-cop-cop boleh, nak tumbuk pun boleh, lepas tu tumis sekejap, ambil 1 kunyit hidup, lepas tu korang blend dengan air\nkatakan lah kuning dia tu tak cukup, tambahkanlah serbuk kunyit yang powder, lepas tu masukkan ayam goreng tadi, letak 1 kotak kecil santan, kan masak lemak kan kena letak santan dek, lepas tu masukkan garam dengan serbuk perasa\nlepas tu letakkan hirisan daun kunyit, lepas tu korang wait, wait, wait and wait, lepas tu kuah dia akan pekat sikit, lepas tu sedia untuk dihidang, yang ni boleh lah makan dengan nasi panas, ya Allah sedap nya, dah lega nak tekak kalau makan panas-panas dengan nasi putih ni, tekak aku memang ni, tengah sakit sekarang ni, tapi ini memang suara Khairul aming, percayalah, ini bukan orang lain, ini memang Khairul Aming, macamana aku nak bagi dia orang percaya ni, hey what\'s up guys\n'),
(48, 48, 48, 'DGzoZYqy8RI.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DGzoZYqy8RI.txt', NULL, NULL, 'txt', 1, 'B032510782', 'ALEEYA MELISSA BINTI ABDULLAH', '2026-07-01 08:41:37', 'Hey what\'s up guys, hari ni kita nak buat Maggi Goreng Basah jadi makan pedas-pedas lepastu perah lima-nipis sikit\nrasa dia sangatlah sedap\nNah, jahat kan bunyi dia? Sangat sedap. Okey, jom kita start\nFirst, korang ambil satu biji bawang merah, dua ulas bawang putih\nTambahkan satu sudu cili kisar\nDan lepas tu tambahkan fish ball dan juga fish cake\nSatu sudu kicap manis, satu sudu tomato, satu sudu sos cili\nDan dia tambahkan air lah. Untuk mee segera, guna depends brand mana yang korang suka\nCumanya untuk dua paket mee segera guna satu paket perencah sahaja\nKalau tak dia masin. Okey lepas tu tambahkan air\nTunggu mee tu kembang dan dia masukkan kita punya udang, telur, cili padi bagi extra pedas sikit\nLepas tu boleh pecahkan telur dia suka pecahkan. baulah kuah itu lagi creamy\nKacau-kacau dan sedia untuk dihidang. Yang ini nak lagi sedap korang pula limau sikit\nSangat sedap. Makan panas-panas macam ni\nYang ni boleh makan untuk moreh\nUntuk moreh bukan sekarang. Sabar ada beberapa jam lagi. Selamat berpuasa\n'),
(49, 49, 49, 'DU5easdAepn.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DU5easdAepn.txt', NULL, NULL, 'txt', 1, 'B032510782', 'ALEEYA MELISSA BINTI ABDULLAH', '2026-07-01 08:41:37', 'Hey, what\'s up, guys?\nSo, kita ada dua lagi menu sahur.\nBelum habis lagi ada dua lagi menu sahur hari ini.\nKita nak buat sardine tumis bersantan\ndengan nasi goreng cili kering.\nSo, first korang ambil dua biji bawang merah,\nlima cili padi,\ntiga lada besar yang dah potong kasar,\nempat gulas bawang putih korang chop-chop-chop.\nLepas itu, kita tumis.\nTumis sampai dia layu sikit.\nMasukkan satu batang serai yang dah diketuk\nand then tambahkan serbuk kunyit sikit.\nSo, korang buka tin sardine itu.\nAmbil dia punya kuah sahaja.\nCampurkan air sikit dengan setengah kotak kecil santan.\nDia punya ikan, letak tepi dulu.\nSo, korang masukkan seasoning garam semua.\nLepas itu, korang tumis sekejap\nsampai dia dah betul-betul pecah minyak macam ini.\nBaru masukkan kita punya ikan.\nSo, ikan ini nak goreng dulu pun boleh.\nTapi, aku tak nak merecik minyak di pagi sahur ni.\nSo, kita letak ikan macam itu sahaja.\nTumis sekejap.\nSambung lagi.\nDan masukkan cili padi untuk naikkan lagi seri dia.\nItu sajalah.\nAnd so, dia untuk dihidang.\nSangatlah sedap dia punya rasa.\nNak lagi kick lagi power.\nPerahkan sikit lima nipis.\nBiar terangkat masa makan time sahur nanti.\nOkay, next kita nak buat nasi goreng cili kering.\nSo, dalam ni korang letak bawang merah, bawang putih.\nIkan bilis sikit.\nDengan cili kering yang kita dah rendam lagi.\nLepas itu, kita chop-chop-chop.\nAku dah boleh letak beg kuning ni untuk aku punya chopper ni.\nBanyak gunanya chop-chop-chop ni.\nKita tambah satu biji telur goreng dulu.\nLepas itu, bawa keluar balik.\nMasukkan bahan yang kita dah chop-chop-chop tadi.\nLepas itu, kita tumis.\nAnd then korang masukkan nasi putih.\nMake sure nasi ni dah sejuk dan baru cantik.\nKami ada tekstur nasi goreng tu.\nLepas itu, masukkan perencah nasi goreng.\nInstant ni tak kisahlah brand mana.\nPakai sikit dan bagi rasa yang keguna nasi goreng kampung.\nTambah satu sudut kicap manis tadi.\nLepas itu, masukkan telur yang kita goreng bersama dengan sayur.\nKacau lagi.\nAnd itu sajalah sedia untuk dihidang.\nBoleh makan macam itu sahaja.\nAtau boleh makan dengan sardine tadi untuk sahur.\nSo, nanti boleh cuba semua resepi untuk sahur.\nAnd sama-samalah kita berpuasa esok.\nSelamat berpuasa.\n'),
(50, 50, 50, 'DHiAC9zyWhj.txt', 'C:/Users/NITRO/eclipse-workspace/nutritional-llm-service/transcript/DHiAC9zyWhj.txt', NULL, NULL, 'txt', 1, 'B032510782', 'ALEEYA MELISSA BINTI ABDULLAH', '2026-07-01 08:41:37', 'Hey what\'s up guys, hari ni kita nak buat marshmallow nougat.\nYang ni antara kuih raya modern yang senang nak buat, kau buat malam raya pun sempat dek.\nCara dia senang je ambil 3 sudu butter cairkan.\nLepas tu masukkan 500g marshmallow.\nYang ni wajib guna kuali non-stick sebab tak nak dia melekat.\nGuna api yang paling kecil.\nSebab yang ni kena sabar-sabar, kacau slow-slow perlahan-perlahan.\nSampailah marshmallow tu cair.\nDan dia masukkan setengah cawan susu tepung dengan setengah sudu kecil garam.\nLepas tu kacau lagi sampai dia larut.\nLepas tu kita masukkan topping yang kita nak lah.\nYang ni kaya gunakan biskut marie, kacang gajus, kacang badam.\nApa lagi ya, kismis.\nNak letak lebihan kurma yang ada kat dapur tu pun boleh.\nTak ada masalah.\nMasukkan sikit-sikit sebab kita nak bagi marshmallow tu tak cair sangat.\nTak pekat sangat.\nYang ni just nice.\nDia macam almost nak mengeras dah.\nLepas tu korang letakkan tray yang dah ditaburkan sikit dengan susu tepung tadi.\nLepas tu letakkan kita punya nougat.\nYang ni je part yang kena pakai tenaga sikit.\nSebab kita kena lenyek, kena tekan, kena padat lagi padat daripada kek batik.\nJadi cara dia kita hempuk-hempukkan dia, tumbuk-tumbukkan dia.\nDum-dum-dum-dum-dum, supaya betul-betul padat kat dalam.\nLepas tu kita biarkan dia rehat dekat luar beberapa jam\nsampai dia betul-betul cool down.\nDan bila dah ready, korang akan notice dia dah mula jadi solid macam ni.\nSo yang ni boleh buka.\nSince kita pakai baking paper kan, dia by right tak melekat sangat lah sebenarnya.\nCuma kita akan tabur sikit susu tepung kat bawah.\nSo dekat bagian atas lepas ni supaya dia tak melekat sangat bila kita potong.\nMacam inilah yang kita tabur sikit kat atas ni kan.\nLepas tu boleh potong ikut lah nak buat size apa, besar ke, kecil ke.\nYang ni cross section dia, cantik kan.\nSo letaklah sikit buah-buah yang kacang-kacang ataupun cranberry yang kering ke apa.\nSupaya warna dia lagi naik lah.\nAnd dia memang chewy and sedap sangat rasa dia.\nBoleh try untuk raya nanti. Selamat mencuba.\n');
